INSERT INTO n64_games (rank, id, title, consoleName, consoleId, totalPlayers, casualPlayers, hardcorePlayers, numAchievements, points, genre, developer, publisher, released, description, icon, boxArt, titleScreen, screenshot, rating) VALUES
  (1, 10003, 'Super Mario 64', 'Nintendo 64', 2, 48917, 48917, 48917, 114, 0, '3D Platforming, Collect-a-thon', NULL, 'Nintendo', '1996-06-23', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/112471.png', 'https://media.retroachievements.org/Images/048358.png', 'https://media.retroachievements.org/Images/048653.png', 'https://media.retroachievements.org/Images/048652.png', 5),
  (2, 10082, 'Super Smash Bros.', 'Nintendo 64', 2, 19010, 19010, 19010, 59, 0, 'Platform Fighting', 'HAL Laboratory', 'Nintendo', '1999-01-21', 'Super Smash Bros. is a series of platform fighting video games published by Nintendo. Created by Masahiro Sakurai, the Super Smash Bros. series is a crossover featuring many characters from other video game series created by Nintendo and other developers. Its gameplay is distinct from traditional fighting games, with players aiming to knock each other off of stages after accumulating damage with numerous attacks. The games have also featured a variety of side modes, including single-player story modes.', 'https://media.retroachievements.org/Images/121474.png', 'https://media.retroachievements.org/Images/091209.png', 'https://media.retroachievements.org/Images/010637.png', 'https://media.retroachievements.org/Images/010638.png', 4.8),
  (3, 10113, 'The Legend of Zelda: Ocarina of Time', 'Nintendo 64', 2, 11045, 11045, 11045, 97, 0, 'Action-Adventure', NULL, 'Nintendo', '1998-11-21', 'The Legend of Zelda: Ocarina of Time is a 1998 action-adventure game developed and published by Nintendo for the Nintendo 64. It was the first Legend of Zelda game with 3D graphics. It was released in Japan and North America in November 1998 and in PAL regions the following month.', 'https://media.retroachievements.org/Images/022051.png', 'https://media.retroachievements.org/Images/048366.png', 'https://media.retroachievements.org/Images/010929.png', 'https://media.retroachievements.org/Images/010930.png', 4.7),
  (4, 10210, 'Banjo-Kazooie', 'Nintendo 64', 2, 9477, 9477, 9477, 60, 0, '3D Platforming, Collect-a-thon', 'Rare', 'Nintendo', '1998-06-29', 'Banjo-Kazooie is a platform game series developed by the British studio Rare. The games focus on the two title characters―Banjo, a male brown bear; and Kazooie, a large female breegull who is typically seen riding in Banjo''s backpack―both of whom are controlled by the player. The games generally involve the pair in conflict with the evil witch Gruntilda Winkybunion. The eponymous first game in the series was released in 1998 to critical acclaim and was followed by Banjo-Tooie (2000), Banjo-Kazooie: Nuts & Bolts (2008), Banjo-Kazooie: Grunty''s Revenge (2003), and Banjo-Pilot (2005), a spinoff kart racing game.', 'https://media.retroachievements.org/Images/091553.png', 'https://media.retroachievements.org/Images/065117.png', 'https://media.retroachievements.org/Images/011034.png', 'https://media.retroachievements.org/Images/011031.png', 4.7),
  (5, 10679, 'The Legend of Zelda: Majora''s Mask', 'Nintendo 64', 2, 9144, 9144, 9144, 96, 0, 'Action-Adventure', 'Nintendo', 'Nintendo', '2000-10-26', 'The Legend of Zelda: Majora''s Mask is a 2000 action-adventure game developed and published by Nintendo for the Nintendo 64. It is the second game in The Legend of Zelda series to use 3D graphics, following Ocarina of Time (1998). Designed by a creative team led by Eiji Aonuma, Yoshiaki Koizumi, and Shigeru Miyamoto, Majora''s Mask was completed in less than two years. It features enhanced graphics and several gameplay changes, but reuses elements and character models from Ocarina of Time, a creative decision made necessary by time constraints.', 'https://media.retroachievements.org/Images/045842.png', 'https://media.retroachievements.org/Images/048359.png', 'https://media.retroachievements.org/Images/015426.png', 'https://media.retroachievements.org/Images/015427.png', 4.7),
  (6, 10075, 'Donkey Kong 64', 'Nintendo 64', 2, 8934, 8934, 8934, 128, 0, '3D Platforming, Collect-a-thon', 'Rare', 'Nintendo', '1999-11-24', 'Donkey Kong 64 is a 1999 platform game developed by Rare and published by Nintendo for the Nintendo 64. It is the first Donkey Kong game to feature 3D gameplay. As the gorilla Donkey Kong, the player explores themed levels to collect items and rescue his kidnapped family members from King K. Rool. The player completes minigames and puzzles as five playable Kong characters—each with their own special abilities—to receive bananas and other collectibles. In multiplayer modes, up to four players can compete in deathmatch and last man standing games.', 'https://media.retroachievements.org/Images/110715.png', 'https://media.retroachievements.org/Images/070527.png', 'https://media.retroachievements.org/Images/024244.png', 'https://media.retroachievements.org/Images/024245.png', 4.7),
  (7, 10246, 'Kirby 64: The Crystal Shards', 'Nintendo 64', 2, 7951, 7951, 7951, 38, 0, '2.5D Platforming', 'HAL Laboratory', 'Nintendo', '2000-03-24', 'Kirby 64: The Crystal Shards is a 2000 platform game developed by HAL Laboratory and published by Nintendo for the Nintendo 64 (N64). It is the first Kirby game to feature 3D computer graphics and follows Kirby as he attempts to reassemble a sacred crystal shattered by Dark Matter. Gameplay is viewed from a 2.5D perspective and is similar to previous Kirby titles; the player traverses levels and obtains powers by eating enemies. Kirby 64 introduces Power Combos, the ability to mix powers to create more powerful ones. In a multiplayer mode, up to four players can compete in three minigames.', 'https://media.retroachievements.org/Images/073571.png', 'https://media.retroachievements.org/Images/048365.png', 'https://media.retroachievements.org/Images/011126.png', 'https://media.retroachievements.org/Images/011127.png', 4.7),
  (8, 10202, 'Diddy Kong Racing', 'Nintendo 64', 2, 7471, 7471, 7471, 94, 0, 'Collect-a-thon, Kart Racing', 'Rare', 'Nintendo', '1997-11-24', 'Diddy Kong Racing is a 1997 kart racing game developed and published by Rare for the Nintendo 64. The game revolves around Diddy Kong and his friends'' attempt to defeat the intergalactic antagonist, a wizard pig named Wizpig, through winning a series of races. The player takes control of any of the featured characters throughout the game. Diddy Kong Racing features five worlds with four racetracks each, and the ability to drive a car, hovercraft, or pilot an aeroplane.', 'https://media.retroachievements.org/Images/040625.png', 'https://media.retroachievements.org/Images/040626.png', 'https://media.retroachievements.org/Images/011105.png', 'https://media.retroachievements.org/Images/011106.png', 4.7),
  (9, 10073, 'GoldenEye 007', 'Nintendo 64', 2, 7292, 7292, 7292, 141, 0, 'First-Person Shooter', 'Rare', 'Nintendo', '1997-08-25', 'GoldenEye 007 is a 1997 first-person shooter game developed by Rare and published by Nintendo for the Nintendo 64. It is based on the 1995 James Bond film GoldenEye, with the player controlling the secret agent James Bond to prevent a criminal syndicate from using a satellite weapon. They navigate a series of levels to complete objectives, such as recovering or destroying objects, while shooting enemies. In a multiplayer mode, up to four players compete in several deathmatch scenarios via split-screen.', 'https://media.retroachievements.org/Images/022585.png', 'https://media.retroachievements.org/Images/066357.png', 'https://media.retroachievements.org/Images/011101.png', 'https://media.retroachievements.org/Images/011103.png', 4.7),
  (10, 10248, 'Star Fox 64', 'Nintendo 64', 2, 5351, 5351, 5351, 50, 0, 'Rail Shooter', NULL, 'Nintendo', '1997-07-01', 'Star Fox 64, known as Lylat Wars in the PAL regions, is a 1997 rail shooter game developed and published by Nintendo for the Nintendo 64. It is the second installment in the Star Fox series and a reboot of the original Star Fox for the Super Nintendo Entertainment System.', 'https://media.retroachievements.org/Images/093951.png', 'https://media.retroachievements.org/Images/048362.png', 'https://media.retroachievements.org/Images/014375.png', 'https://media.retroachievements.org/Images/014379.png', 4.6),
  (11, 10173, 'Yoshi''s Story', 'Nintendo 64', 2, 4703, 4703, 4703, 93, 0, '2D Platforming, Collect-a-thon', 'Nintendo', 'Nintendo', '1998-03-01', 'Yoshi''s Story is a 1997 platform game published and developed by Nintendo for the Nintendo 64. It was released in Japan in December 1997, and worldwide the following year. The game has been subsequently re-released on the Wii, Wii U, and Nintendo Switch.', 'https://media.retroachievements.org/Images/044181.png', 'https://media.retroachievements.org/Images/048368.png', 'https://media.retroachievements.org/Images/011212.png', 'https://media.retroachievements.org/Images/011211.png', 4.6),
  (12, 10263, 'Mario Party', 'Nintendo 64', 2, 3481, 3481, 3481, 56, 0, 'Board Game, Party', 'Hudson Soft', 'Nintendo', '1998-12-18', 'Mario Party is a series of party video games created by Hudson Soft and owned by Nintendo. It features characters from the Mario franchise in which up to four local players or computer-controlled characters compete in a board game interspersed with minigames. Designed by Shigeru Miyamoto, and directed by Kenji Kikuchi, the games are currently developed by Nintendo Cube and published by Nintendo, being previously developed by Hudson Soft. The series is known for its party game elements, including the often unpredictable multiplayer game modes that allow play with up to four, and sometimes eight, human players or CPUs.', 'https://media.retroachievements.org/Images/040160.png', 'https://media.retroachievements.org/Images/011086.png', 'https://media.retroachievements.org/Images/011084.png', 'https://media.retroachievements.org/Images/011085.png', 4.5),
  (13, 10617, 'Wave Race 64', 'Nintendo 64', 2, 3228, 3228, 3228, 73, 0, 'Racing', NULL, 'Nintendo', '1996-09-27', 'Wave Race 64 is a 1996 racing video game developed and published by Nintendo for the Nintendo 64. It is the second entry in the Wave Race series following the 1992 Game Boy game Wave Race. Gameplay involves the player racing on a personal watercraft on a variety of courses while successfully manoeuvring the vehicle around various buoys. A multiplayer mode where two players can compete against each other on a chosen course is also included. The game supports the Controller Pak, which allows players to transfer saved data from one game cartridge to another. The game is presented in a letterboxed 14:9 aspect ratio.', 'https://media.retroachievements.org/Images/019034.png', 'https://media.retroachievements.org/Images/019035.png', 'https://media.retroachievements.org/Images/019036.png', 'https://media.retroachievements.org/Images/019037.png', 4.5),
  (14, 10667, 'Castlevania', 'Nintendo 64', 2, 3024, 3024, 3024, 52, 0, 'Action-Adventure, 3D Platforming', 'Konami', 'Konami', '1999-01-26', 'Castlevania, known in Japan as Akumajō Dracula, is a gothic horror action-adventure video game series and media franchise created by Hitoshi Akamatsu and published by Konami. The series is largely set in the castle of Count Dracula, who wages an eternal war against humanity and comes into conflict with the world''s vampire hunters, principally including the Belmont clan, wielders of the mystical whip known as the "Vampire Killer."', 'https://media.retroachievements.org/Images/091411.png', 'https://media.retroachievements.org/Images/070351.png', 'https://media.retroachievements.org/Images/070353.png', 'https://media.retroachievements.org/Images/070352.png', 4.5),
  (15, 10133, 'F-Zero X', 'Nintendo 64', 2, 2892, 2892, 2892, 74, 0, 'Arcade Racing', NULL, 'Nintendo', '1998-07-14', 'F-Zero X is a 1998 racing game developed and published by Nintendo for the Nintendo 64. It is the sequel to the original F-Zero (1990), and the first F-Zero game with 3D graphics. It has a steep learning curve and its gameplay experience is similar to that of the original. The F-Zero X Expansion Kit, an expansion pack for the 64DD featuring 12 more tracks and track and vehicle editors, was released in Japan in 2000.', 'https://media.retroachievements.org/Images/046476.png', 'https://media.retroachievements.org/Images/048360.png', 'https://media.retroachievements.org/Images/014763.png', 'https://media.retroachievements.org/Images/014764.png', 4.5),
  (16, 10211, 'Banjo-Tooie', 'Nintendo 64', 2, 2874, 2874, 2874, 110, 0, '3D Platforming, Collect-a-thon', 'Rare', 'Nintendo', '2000-11-20', 'Banjo-Tooie is a 2000 platform game developed by Rare and published by Nintendo for the Nintendo 64 console. It is the second game in the Banjo-Kazooie series and the sequel to Banjo-Kazooie. The game follows the returning protagonists Banjo and Kazooie as they attempt to stop the plans of the witch Gruntilda and two of her sisters, who intend to vaporise the inhabitants of the game''s island setting. The game features worlds significantly larger than those of its predecessor, requiring the player to complete challenges such as solving puzzles, jumping over obstacles, collecting items, and defeating opponents. It also includes a Widescreen format, and a multiplayer mode in which up to four players can compete in several minigames repurposed from the main campaign.', 'https://media.retroachievements.org/Images/091555.png', 'https://media.retroachievements.org/Images/096336.png', 'https://media.retroachievements.org/Images/018548.png', 'https://media.retroachievements.org/Images/019194.png', 4.5),
  (17, 10181, 'Pokémon Stadium', 'Nintendo 64', 2, 2700, 2700, 2700, 72, 0, 'Turn-Based Strategy', 'HAL Laboratory', 'Nintendo', '1999-04-30', 'Pokémon Stadium is a 1999 strategy video game developed and published by Nintendo for the Nintendo 64. The gameplay revolves around a 3D turn-based battling system using the 151 Pokémon from the Game Boy games Pokémon Red, Blue, and Yellow, with several in-game challenges for players to overcome. The game includes four "Cups", each of which is a series of three-on-three Pokémon battles against an ordered lineup of opponents. The "Gym Leader Castle" mode involves battles against several boss opponents who appeared in the Game Boy games. Pokémon Stadium also features mini-games and numerous features available through its compatibility with Pokémon Red, Blue, and Yellow. Using the Transfer Pak accessory that was bundled with the game, players are able to view, organize, store, trade, and battle using Pokémon uploaded from Pokémon Red, Blue, and Yellow.', 'https://media.retroachievements.org/Images/026595.png', 'https://media.retroachievements.org/Images/010940.png', 'https://media.retroachievements.org/Images/011020.png', 'https://media.retroachievements.org/Images/011021.png', 4.5),
  (18, 10270, 'Pokémon Puzzle League', 'Nintendo 64', 2, 2677, 2677, 2677, 52, 0, NULL, NULL, 'Nintendo', '2000-09-25', 'Pokémon Puzzle League is a puzzle video game in the Puzzle League series developed by Nintendo Software Technology and published by Nintendo for the Nintendo 64. Released in North America on September 25, 2000, and in Europe on March 2, 2001, its Puzzle League-based gameplay has a focus on puzzle-based strategy in the game''s grid-based format. To advance to new levels, players are required to combat the game''s trainers and gym leaders, similar to the ones featured in Pokémon Red, Blue, and Yellow. One of several games based on the Pokémon anime, it features lead protagonist Ash Ketchum, his Pikachu, his companions Brock and Misty, the Kanto Gym Leaders, and other characters from the series.', 'https://media.retroachievements.org/Images/109181.png', 'https://media.retroachievements.org/Images/014333.png', 'https://media.retroachievements.org/Images/016162.png', 'https://media.retroachievements.org/Images/016163.png', 4.5),
  (19, 10648, 'Star Wars: Rogue Squadron', 'Nintendo 64', 2, 2516, 2516, 2516, 49, 0, 'Action, Shooter', 'Factor 5, LucasArts | Lucasfilm', 'LucasArts | Lucasfilm', '1998-12-07', 'Star Wars: Rogue Squadron or Star Wars: Rogue Squadron 3D is an arcade-style flight action game co-developed by Factor 5 and LucasArts. The first of the Rogue Squadron trilogy, it was published by LucasArts and Nintendo and released for Microsoft Windows and Nintendo 64 in December 1998. The game''s story was influenced by the Star Wars: X-wing – Rogue Squadron comics and is set in the fictional Star Wars galaxy, taking place primarily between events in the films Star Wars and The Empire Strikes Back. The player controls Luke Skywalker, commander of the elite X-wing pilots known as Rogue Squadron. As the game progresses, Skywalker and Rogue Squadron fight the Galactic Empire in 16 missions across various planets.', 'https://media.retroachievements.org/Images/111879.png', 'https://media.retroachievements.org/Images/019616.png', 'https://media.retroachievements.org/Images/019617.png', 'https://media.retroachievements.org/Images/045695.png', 4.5),
  (20, 10259, 'Mario Golf', 'Nintendo 64', 2, 2026, 2026, 2026, 115, 0, 'Sports - Golf', 'Camelot Software Planning', 'Nintendo', '1999-06-30', '  There have been numerous sports games featuring Mario characters, based, among others, on tennis, golf, baseball, soccer, and various sports featured in the Olympic Games.', 'https://media.retroachievements.org/Images/027468.png', 'https://media.retroachievements.org/Images/011029.png', 'https://media.retroachievements.org/Images/011027.png', 'https://media.retroachievements.org/Images/011028.png', 4.4),
  (21, 10110, 'Perfect Dark', 'Nintendo 64', 2, 1996, 1996, 1996, 130, 0, 'First-Person Shooter, Stealth', 'Rare', 'Rare', '2000-05-22', 'Perfect Dark is a 2000 first-person shooter game developed and published by Rare for the Nintendo 64. The first game of the Perfect Dark series, it follows Joanna Dark, an agent of the Carrington Institute research centre, as she attempts to stop an extraterrestrial conspiracy by rival corporation dataDyne. The game features a campaign mode where the player must complete a series of levels to progress through the story, as well as a range of multiplayer options, including a co-operative mode and traditional deathmatch settings with computer-controlled bots.', 'https://media.retroachievements.org/Images/107798.png', 'https://media.retroachievements.org/Images/011065.png', 'https://media.retroachievements.org/Images/011062.png', 'https://media.retroachievements.org/Images/011064.png', 4.4),
  (22, 10264, 'Mario Party 2', 'Nintendo 64', 2, 1967, 1967, 1967, 45, 0, 'Board Game, Party', 'Hudson Soft', 'Nintendo', '1999-12-17', 'Mario Party 2 is a 1999 party video game developed by Hudson Soft and published by Nintendo for the Nintendo 64. The second game in the Mario Party series, it was released in Japan on December 17, 1999, North America on January 24, 2000, and in PAL regions on October 13, 2000. The game received mostly positive reviews from critics, who praised the improvements over the original, as well as the multiplayer and minigames, but criticized the lack of originality, while graphics received a mixed to positive response.', 'https://media.retroachievements.org/Images/040217.png', 'https://media.retroachievements.org/Images/014654.png', 'https://media.retroachievements.org/Images/014651.png', 'https://media.retroachievements.org/Images/028446.png', 4.4),
  (23, 10162, 'Blast Corps', 'Nintendo 64', 2, 1957, 1957, 1957, 24, 0, 'Action, Puzzle', 'Rare', 'Nintendo', '1997-02-28', 'Blast Corps is an action game developed by Rare and published by Nintendo for the Nintendo 64. The player uses vehicles to destroy buildings in the path of a runaway nuclear missile carrier. In the game''s 57 levels, the player solves puzzles by transferring between vehicles to move objects and bridge gaps. It was released in March 1997 in Japan and North America. A wider release followed at the end of that year.', 'https://media.retroachievements.org/Images/125239.png', 'https://media.retroachievements.org/Images/014502.png', 'https://media.retroachievements.org/Images/010784.png', 'https://media.retroachievements.org/Images/010787.png', 4.4),
  (24, 17500, '~Hack~ B3313', 'Nintendo 64', 2, 1880, 1880, 1880, 298, 0, '3D Platforming, Collect-a-thon', 'chrisrlillo', 'Hack - Super Mario 64', '2021-04-26', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/068471.png', 'https://media.retroachievements.org/Images/068468.png', 'https://media.retroachievements.org/Images/068470.png', 'https://media.retroachievements.org/Images/068469.png', 4.4),
  (25, 15964, '~Hack~ Smash Remix', 'Nintendo 64', 2, 1775, 1775, 1775, 201, 0, 'Platform Fighting', 'Smash Remix Team', 'Hack - Super Smash Bros.', '2020-12-18', 'Mortal Kombat is an American media franchise centered on a series of fighting video games originally developed by Midway Games in 1992.', 'https://media.retroachievements.org/Images/121623.png', 'https://media.retroachievements.org/Images/101880.png', 'https://media.retroachievements.org/Images/035261.png', 'https://media.retroachievements.org/Images/035258.png', 4.4),
  (26, 10108, 'Mario Party 3', 'Nintendo 64', 2, 1722, 1722, 1722, 72, 0, 'Board Game, Party', 'Hudson Soft', 'Nintendo', '2000-12-07', 'Mario Party 3 is a 2000 party video game developed by Hudson Soft and published by Nintendo for the Nintendo 64. The third installment in the Mario Party series, it was first released in Japan on December 7, 2000, in North America on May 7, 2001, in Australia on September 3, 2001, and in Europe on November 16, 2001. As with the previous installments, the player chooses between eight playable characters: Mario, Luigi, Princess Peach, Yoshi, Wario, and Donkey Kong from the first two games, alongside newcomers Princess Daisy and Waluigi. The game introduces duel maps, where two players try to lower each other''s stamina to zero using non-player characters such as Chain Chomps.', 'https://media.retroachievements.org/Images/040226.png', 'https://media.retroachievements.org/Images/011082.png', 'https://media.retroachievements.org/Images/011080.png', 'https://media.retroachievements.org/Images/026385.png', 4.4),
  (27, 10153, 'Star Wars: Shadows of the Empire', 'Nintendo 64', 2, 1663, 1663, 1663, 38, 0, 'Action', 'LucasArts | Lucasfilm', 'Nintendo, LucasArts | Lucasfilm', '1996-12-03', 'Star Wars: Shadows of the Empire is a 1996 multimedia project created by Lucasfilm. The idea was to create a story set between the films The Empire Strikes Back and Return of the Jedi, and to explore all commercial possibilities of a full motion picture release without actually making a film. The venture was intended to reinvigorate interest in the franchise ahead of the theatrical Special Editions of the Star Wars trilogy released the following year.', 'https://media.retroachievements.org/Images/055047.png', 'https://media.retroachievements.org/Images/010757.png', 'https://media.retroachievements.org/Images/010755.png', 'https://media.retroachievements.org/Images/010756.png', 4.4),
  (28, 12984, 'The New Tetris', 'Nintendo 64', 2, 1654, 1654, 1654, 27, 0, 'Falling Block Puzzle', 'H2O Entertainment', 'Nintendo', '1999-07-31', 'The New Tetris is a 1999 puzzle video game developed by H2O Entertainment and Blue Planet Software and published by Nintendo for the Nintendo 64. An entry in the Tetris series, it showcases scenic fly-bys of structures, such as the Sphinx, the Pantheon, Saint Basil''s Cathedral, a Mayan temple, and others, rendered in real-time. Achieving this level of quality was relatively challenging for the Nintendo 64 hardware. The New Tetris features a multiplayer mode with up to four players and an electronic dance music soundtrack by Neil Voss, who also composed the music for Tetrisphere.', 'https://media.retroachievements.org/Images/052609.png', 'https://media.retroachievements.org/Images/018277.png', 'https://media.retroachievements.org/Images/018278.png', 'https://media.retroachievements.org/Images/018279.png', 4.4),
  (29, 10238, 'Road Rash 64', 'Nintendo 64', 2, 1648, 1648, 1648, 52, 0, 'Racing', 'Pacific Coast Power and Light', 'THQ', '1999-01-01', 'Road Rash 64 is a 1999 racing game developed by Pacific Coast Power and Light and published by THQ for the Nintendo 64. The game is the fifth of seven entries in the Road Rash series of video games, the only entry to be published by THQ and the only entry to be released for the Nintendo 64 platform.', 'https://media.retroachievements.org/Images/083611.png', 'https://media.retroachievements.org/Images/044926.png', 'https://media.retroachievements.org/Images/044928.png', 'https://media.retroachievements.org/Images/044927.png', 4.4),
  (30, 10258, 'Pokémon Stadium 2', 'Nintendo 64', 2, 1617, 1617, 1617, 109, 0, 'Turn-Based Strategy', 'HAL Laboratory', 'Nintendo', '2000-12-14', 'Pokémon Stadium 2, known in Japan as Pokémon Stadium Gold & Silver, is a strategy video game developed and published by Nintendo for the Nintendo 64. It is the third game in the Pokémon Stadium series, following prior releases Pocket Monsters Stadium and Pokémon Stadium. It features all 251 Pokémon from the first and second generations of the franchise, and allows for players to battle either with other players or against computer-controlled opponents. Like its predecessor, Pokémon Stadium 2 is compatible with the Transfer Pak accessory, allowing players to use Pokémon trained in the three original Game Boy Pokémon games and the three Game Boy Color games.', 'https://media.retroachievements.org/Images/115110.png', 'https://media.retroachievements.org/Images/011026.png', 'https://media.retroachievements.org/Images/011022.png', 'https://media.retroachievements.org/Images/011024.png', 4.4),
  (31, 10077, 'Resident Evil 2', 'Nintendo 64', 2, 1460, 1460, 1460, 120, 0, 'Survival Horror', 'Capcom', 'Capcom', '1999-11-16', 'Resident Evil 2 is a 1998 survival horror video game developed and published by Capcom for the PlayStation. It is the second main installment in the Resident Evil series. The player controls rookie cop Leon S. Kennedy and college student Claire Redfield, who must escape Raccoon City after its citizens are transformed into zombies by a biological weapon two months after the events of the original Resident Evil. The gameplay focuses on exploration, puzzles, and combat; the main difference from its predecessor are the branching paths, with each player character having unique storylines, partners and obstacles.', 'https://media.retroachievements.org/Images/069061.png', 'https://media.retroachievements.org/Images/016137.png', 'https://media.retroachievements.org/Images/010870.png', 'https://media.retroachievements.org/Images/010872.png', 4.4),
  (32, 27577, '~Hack~ Shotgun Mario 64', 'Nintendo 64', 2, 1387, 1387, 1387, 64, 0, '3D Platforming', 'Dan_GPTV', 'Hack - Super Mario 64', '2023-10-22', 'Celeste 64: Fragments of the Mountain is a 2024 3D platformer video game developed and published by Canadian indie studio Extremely OK Games for Linux, macOS and Microsoft Windows. The game was developed during a week-long game jam, in which it released in celebration of the sixth anniversary of the 2018 video game Celeste. The game released January 29, 2024, acting as semi-sequel to that game and a continuation to its narrative.', 'https://media.retroachievements.org/Images/086766.png', 'https://media.retroachievements.org/Images/105646.png', 'https://media.retroachievements.org/Images/087056.png', 'https://media.retroachievements.org/Images/087055.png', 4.4),
  (33, 10085, 'Cruis''n USA', 'Nintendo 64', 2, 1361, 1361, 1361, 43, 0, 'Arcade Racing', 'Williams', 'Nintendo', '1996-10-31', 'Cruis''n USA is a racing video game developed by TV Games Inc. and published by Nintendo. It was first released in arcades in 1994 by Midway Games, with a port to the Nintendo 64 developed by Leland Interactive Media released in 1996. It is the first game in the Cruis''n series, and features races set in locations across the Continental United States.', 'https://media.retroachievements.org/Images/044270.png', 'https://media.retroachievements.org/Images/010998.png', 'https://media.retroachievements.org/Images/010995.png', 'https://media.retroachievements.org/Images/010996.png', 4.4),
  (34, 10116, 'Mortal Kombat 4', 'Nintendo 64', 2, 1354, 1354, 1354, 130, 0, '3D Fighting', 'Eurocom', 'Midway', '1998-06-23', 'Mortal Kombat 4 is a 1997 fighting game developed and published by Midway for arcades. It is the fourth main installment in the Mortal Kombat franchise, and a sequel to 1995''s Mortal Kombat 3. It is also the first title in the series to use 3D computer graphics, as well as the last in the series to have an arcade release. The game was ported to the PlayStation, Nintendo 64, Microsoft Windows, and Game Boy Color in 1998, followed by an updated version, titled Mortal Kombat Gold, for the Dreamcast in 1999.', 'https://media.retroachievements.org/Images/123570.png', 'https://media.retroachievements.org/Images/042460.png', 'https://media.retroachievements.org/Images/042458.png', 'https://media.retroachievements.org/Images/012068.png', 4.4),
  (35, 10148, 'Army Men: Sarge''s Heroes', 'Nintendo 64', 2, 1337, 1337, 1337, 65, 0, 'Third-Person Shooter', 'The 3DO Company', 'The 3DO Company', '1999-09-28', 'Army Men: Sarge''s Heroes is a 1999 third-person shooter video game and the fourth entry in The 3DO Company''s Army Men series, which are based on the green plastic figures of the same name. Its Nintendo 64 and PlayStation versions were developed and published by The 3DO Company. The port for the Dreamcast was developed by Saffire and published by Midway, while another for Microsoft Windows was published by GT Interactive.', 'https://media.retroachievements.org/Images/107432.png', 'https://media.retroachievements.org/Images/079976.png', 'https://media.retroachievements.org/Images/015292.png', 'https://media.retroachievements.org/Images/015293.png', 4.3),
  (36, 10256, 'Mickey''s Speedway USA', 'Nintendo 64', 2, 1308, 1308, 1308, 72, 0, 'Kart Racing', 'Rare', 'Nintendo', '2000-11-13', 'Mickey''s Speedway USA is a kart racing game developed by Rare and published by Nintendo for the Nintendo 64 and Game Boy Color. It is Rare and Nintendo''s second collaboration with Disney Interactive following Mickey''s Racing Adventure (1999), and features characters from the Mickey Mouse universe racing across the United States. The Nintendo 64 game released in November 2000 to mixed reception, while the Game Boy Color version followed in March 2001.', 'https://media.retroachievements.org/Images/112014.png', 'https://media.retroachievements.org/Images/018506.png', 'https://media.retroachievements.org/Images/028670.png', 'https://media.retroachievements.org/Images/028671.png', 4.3),
  (37, 10309, 'Glover', 'Nintendo 64', 2, 1287, 1287, 1287, 49, 0, '3D Platforming, Collect-a-thon', 'Blitz Games', 'Hasbro Interactive', '1998-11-16', 'Glover is a 1998 puzzle-platformer developed by Interactive Studios and published by Hasbro Interactive for the Nintendo 64 and Windows in 1998, and for the PlayStation in 1999. The game follows a magical, four-fingered glove named Glover in his quest to restore the Crystal Kingdom by retrieving crystals that were lost.', 'https://media.retroachievements.org/Images/069876.png', 'https://media.retroachievements.org/Images/025061.png', 'https://media.retroachievements.org/Images/025064.png', 'https://media.retroachievements.org/Images/099202.png', 4.3),
  (38, 10120, 'Bomberman 64', 'Nintendo 64', 2, 1242, 1242, 1242, 69, 0, 'Action, Puzzle', 'Hudson Soft', 'Nintendo', '1997-09-26', 'Bomberman 64 is a video game developed and published by Hudson Soft as "Baku Bomberman" in Japan, and published by Nintendo as "Bomberman 64" in North America and Europe for the Nintendo 64. In Japan the "Bomberman 64" name was chosen for another game, the fourth Japanese Bomberman entry in the series. The 1997 game was released in Europe and North America in November and December 1997, respectively. While the game never saw a release on the Wii''s Virtual Console service, it was released on the Wii U Virtual Console in both Europe and North America in March 2017 followed by Japan in June 2017.', 'https://media.retroachievements.org/Images/053933.png', 'https://media.retroachievements.org/Images/011136.png', 'https://media.retroachievements.org/Images/011137.png', 'https://media.retroachievements.org/Images/011138.png', 4.3),
  (39, 10328, 'South Park', 'Nintendo 64', 2, 1219, 1219, 1219, 53, 0, 'First-Person Shooter', 'Iguana Entertainment', 'Acclaim', '1998-12-12', 'South Park is an American animated sitcom created by Trey Parker and Matt Stone for Comedy Central. The series revolves around four boys—Stan Marsh, Kyle Broflovski, Eric Cartman, and Kenny McCormick—and their adventures in and around the titular Colorado town. South Park also features many recurring characters. The series became infamous for its profanity and dark, surreal humor that satirizes a large range of subject matter.', 'https://media.retroachievements.org/Images/088517.png', 'https://media.retroachievements.org/Images/011926.png', 'https://media.retroachievements.org/Images/011927.png', 'https://media.retroachievements.org/Images/011928.png', 4.3),
  (40, 10157, 'Harvest Moon 64', 'Nintendo 64', 2, 1190, 1190, 1190, 80, 0, 'Life Simulation', 'Marvelous Interactive', 'Natsume', '1999-02-05', 'Harvest Moon 64, released in Japan as Bokujō Monogatari 2 (牧場物語2), is a 1999 farm simulation video game developed by Victor Interactive Software for the Nintendo 64 console. It was published by Victor Interactive in Japan and by Natsume Inc. in North America. It is the third game in the Story of Seasons series.', 'https://media.retroachievements.org/Images/109404.png', 'https://media.retroachievements.org/Images/010767.png', 'https://media.retroachievements.org/Images/010765.png', 'https://media.retroachievements.org/Images/010766.png', 4.3),
  (41, 10093, 'Hexen', 'Nintendo 64', 2, 1179, 1179, 1179, 66, 0, 'First-Person Shooter', 'Software Creations', 'Atari', '1997-05-31', 'Hexen: Beyond Heretic is a 1995 first-person shooter video game developed by Raven Software and published by id Software for MS-DOS. It is the sequel to 1994''s Heretic, and the second game in Raven Software''s "Serpent Riders" trilogy, which culminated with Hexen II. The title comes from the German noun Hexen, which means "witches", and/or the verb hexen, which means "to cast a spell". Game producer John Romero stated that a third, unreleased game in this series was to be called Hecatomb.', 'https://media.retroachievements.org/Images/055046.png', 'https://media.retroachievements.org/Images/014510.png', 'https://media.retroachievements.org/Images/010999.png', 'https://media.retroachievements.org/Images/011000.png', 4.3),
  (42, 16231, 'Donald Duck: Goin'' Quackers', 'Nintendo 64', 2, 1163, 1163, 1163, 64, 0, '3D Platforming', 'Ubisoft', 'Ubisoft', '2000-12-08', 'Donald Duck: Goin'' Quackers is a 2000 platform game developed and published by Ubi Soft for various consoles and Windows-based personal computers. A version with the same title was released for the Game Boy Color, before it was retitled Donald Duck Advance for the Game Boy Advance. Reviews praised the music, backgrounds and animations, noting the short length and low difficulty as more fun for children.', 'https://media.retroachievements.org/Images/113851.png', 'https://media.retroachievements.org/Images/033332.png', 'https://media.retroachievements.org/Images/033330.png', 'https://media.retroachievements.org/Images/033331.png', 4.3),
  (43, 10080, 'Doom 64', 'Nintendo 64', 2, 1162, 1162, 1162, 88, 0, 'First-Person Shooter', 'Midway', 'Midway', '1997-03-31', 'Doom 64 is a 1997 first-person shooter game developed and published by Midway Games for the Nintendo 64. It is the second spin-off in id Software''s Doom series after Final Doom (1996), and the fourth game in the series overall.', 'https://media.retroachievements.org/Images/010650.png', 'https://media.retroachievements.org/Images/066513.png', 'https://media.retroachievements.org/Images/010646.png', 'https://media.retroachievements.org/Images/010647.png', 4.3),
  (44, 10166, 'Cruis''n World', 'Nintendo 64', 2, 1157, 1157, 1157, 76, 0, 'Arcade Racing', 'Eurocom', 'Nintendo', '1998-09-28', 'Cruis''n World is a 1996 racing game developed by Midway Games and published by Nintendo. It is the sequel to the 1994 arcade racer Cruis''n USA. A port for the Nintendo 64 developed by Eurocom was released in 1998, and was the best received of the Cruis''n ports.', 'https://media.retroachievements.org/Images/073208.png', 'https://media.retroachievements.org/Images/064742.png', 'https://media.retroachievements.org/Images/010788.png', 'https://media.retroachievements.org/Images/010789.png', 4.3),
  (45, 10081, 'Mystical Ninja Starring Goemon', 'Nintendo 64', 2, 1149, 1149, 1149, 44, 0, '3D Platforming', 'Konami', 'Konami', '1997-08-07', 'Mystical Ninja Starring Goemon is a 1997 platform action-adventure game developed by Konami Computer Entertainment Osaka and published by Konami for the Nintendo 64. The second Ganbare Goemon game released in North America and Europe, and the twelfth mainline installment overall, follows The Legend of the Mystical Ninja and features hybrid elements of platform games and action-adventure games.', 'https://media.retroachievements.org/Images/094020.png', 'https://media.retroachievements.org/Images/050419.png', 'https://media.retroachievements.org/Images/016081.png', 'https://media.retroachievements.org/Images/016082.png', 4.3),
  (46, 30, 'Jet Force Gemini', 'Nintendo 64', 2, 1125, 1125, 1125, 63, 0, 'Collect-a-thon, Third-Person Shooter', 'Rare', 'Rare', '1999-09-01', 'Jet Force Gemini is a 1999 third-person shooter game developed and published by Rare for the Nintendo 64. The game follows the story of three members of a galactic law enforcement team as they try to stop a horde of drones led by an insectoid called Mizar. It features a single-player mode where the player must explore a galaxy and save Tribals, a race of survivors who have been enslaved and imprisoned by Mizar, and places strong emphasis on shooting large numbers of enemies while dodging their attacks. The game includes a multiplayer mode where two to four players can compete in traditional deathmatch games.', 'https://media.retroachievements.org/Images/112099.png', 'https://media.retroachievements.org/Images/051950.png', 'https://media.retroachievements.org/Images/020099.png', 'https://media.retroachievements.org/Images/017046.png', 4.3),
  (47, 10546, '~Hack~ Super Mario 74', 'Nintendo 64', 2, 1097, 1097, 1097, 58, 0, '3D Platforming', 'Hacker - Lugmillord', 'Hack - Super Mario 64', '2011-06-27', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/085735.png', 'https://media.retroachievements.org/Images/017494.png', 'https://media.retroachievements.org/Images/017493.png', 'https://media.retroachievements.org/Images/085736.png', 4.3),
  (48, 10912, 'Hot Wheels: Turbo Racing', 'Nintendo 64', 2, 1093, 1093, 1093, 63, 0, 'Arcade Racing', 'Stormfront Studios', 'Electronic Arts', '1999-08-31', 'Hot Wheels Turbo Racing is a racing video game released for the Nintendo 64 and PlayStation in 1999. It features 40 cars based on the Hot Wheels series of toys. It also features Kyle Petty''s 1999 NASCAR stock car, as it was sponsored by Hot Wheels. The game features music from artists like Primus, Metallica, The Reverend Horton Heat and Mix Master Mike.', 'https://media.retroachievements.org/Images/073192.png', 'https://media.retroachievements.org/Images/022299.png', 'https://media.retroachievements.org/Images/022300.png', 'https://media.retroachievements.org/Images/022301.png', 4.3),
  (49, 10331, 'WWF No Mercy', 'Nintendo 64', 2, 1074, 1074, 1074, 36, 0, 'Sports - Wrestling', 'AKI Corporation', 'THQ', '2000-11-17', 'WWE No Mercy, also known as NXT No Mercy since 2023, is a professional wrestling event produced by WWE, a professional wrestling promotion based in Connecticut. The first No Mercy was held on May 16, 1999, in Manchester, England, and was the only No Mercy event produced in the United Kingdom. A second No Mercy was then held in October that year in Cleveland, Ohio, United States. Beginning with this second event, No Mercy became the annual October pay-per-view (PPV) until 2008. The event was then discontinued and replaced by Hell in a Cell in 2009. After eight years, No Mercy was reinstated in October 2016. However, No Mercy was again discontinued after the September 2017 event, as WWE reduced the amount of yearly PPVs held after they had ended the production of brand-exclusive PPVs following WrestleMania 34 in 2018. In 2023, WWE again revived the event, this time for its developmental brand, NXT, in September.', 'https://media.retroachievements.org/Images/054255.png', 'https://media.retroachievements.org/Images/012048.png', 'https://media.retroachievements.org/Images/012047.png', 'https://media.retroachievements.org/Images/012049.png', 4.3),
  (50, 10135, '007: The World Is Not Enough', 'Nintendo 64', 2, 1036, 1036, 1036, 100, 0, 'First-Person Shooter', 'Eurocom', 'Electronic Arts', '2000-11-01', 'The World Is Not Enough is a 2000 first-person shooter video game developed by Eurocom and published by Electronic Arts. It is based on the 1999 film of the same name. It was released for the Nintendo 64 in North America on October 17, 2000 and in Europe on December 8, 2000. The game was also released for the PlayStation in November. The game features a single-player campaign in which players assume the role of secret agent James Bond as he fights to stop a terrorist from triggering a nuclear meltdown in the waters of Istanbul. It includes a split-screen multiplayer mode where up to four players can compete in different types of deathmatch and objective-based games.', 'https://media.retroachievements.org/Images/071854.png', 'https://media.retroachievements.org/Images/071811.png', 'https://media.retroachievements.org/Images/023342.png', 'https://media.retroachievements.org/Images/023344.png', 4.3),
  (51, 10329, 'Rampage 2: Universal Tour', 'Nintendo 64', 2, 1030, 1030, 1030, 25, 0, 'Action', 'Avalanche Software', 'Midway', '1999-03-01', 'Rampage 2: Universal Tour is a 1999 action game developed by Avalanche Software and published by Midway. It is the third game in the Rampage series and a sequel to 1997''s Rampage World Tour.', 'https://media.retroachievements.org/Images/098726.png', 'https://media.retroachievements.org/Images/014515.png', 'https://media.retroachievements.org/Images/011934.png', 'https://media.retroachievements.org/Images/041267.png', 4.3),
  (52, 10871, 'Magical Tetris Challenge', 'Nintendo 64', 2, 1025, 1025, 1025, 34, 0, NULL, 'Capcom', 'Capcom', '1998-11-20', 'Magical Tetris Challenge is a 1998 puzzle video game developed and published by Capcom for arcades. It was ported to the Nintendo 64, Game Boy Color and PlayStation. It is a version of Tetris featuring Disney characters. It is one of the few Nintendo 64 games to be entirely in 2D, in addition to being Capcom''s first game for the console. The Japanese arcade cabinet and cover art was done by Kenichi Sudo, while the North American cover art was done by Robert Griggs.', 'https://media.retroachievements.org/Images/047644.png', 'https://media.retroachievements.org/Images/014730.png', 'https://media.retroachievements.org/Images/014731.png', 'https://media.retroachievements.org/Images/014732.png', 4.3),
  (53, 10199, 'Snowboard Kids', 'Nintendo 64', 2, 1005, 1005, 1005, 25, 0, 'Extreme Sports - Snowboarding, Kart Racing', 'Racjin | Racdym', 'Atlus', '1998-02-01', 'Snowboard Kids , is a snowboarding video game for the Nintendo 64. It was developed by Racdym and published by Atlus. Many reviewers compared its style to that of the Mario Kart series. An enhanced port, Snowboard Kids Plus, was released in Japan in January 1999 for the PlayStation.', 'https://media.retroachievements.org/Images/085925.png', 'https://media.retroachievements.org/Images/014516.png', 'https://media.retroachievements.org/Images/010970.png', 'https://media.retroachievements.org/Images/010971.png', 4.3),
  (54, 10448, 'WCW/nWo Revenge', 'Nintendo 64', 2, 999, 999, 999, 42, 0, 'Sports - Wrestling', 'Asmik Ace Entertainment/AKI Corporation', 'THQ', '1998-10-26', 'WCW/nWo Revenge is a professional wrestling video game developed by Asmik Ace Entertainment and AKI Corporation and released by THQ in 1998 for the Nintendo 64 game console. It is the sequel to 1997''s WCW vs. nWo: World Tour. Like its predecessor, Revenge features AKI''s proprietary grappling system; as well as heavily improved graphics, a championship mode, and a large roster of wrestlers.', 'https://media.retroachievements.org/Images/082170.png', 'https://media.retroachievements.org/Images/027568.png', 'https://media.retroachievements.org/Images/044132.png', 'https://media.retroachievements.org/Images/044133.png', 4.3),
  (55, 10298, 'Tarzan', 'Nintendo 64', 2, 992, 992, 992, 45, 0, '2.5D Platforming', 'Eurocom', 'Activision', '2000-01-31', 'Tarzan is a fictional character, a feral child raised in the Congo Basin by the Mangani great apes; he later experiences civilization, only to reject it and return to the wild as a heroic adventurer.', 'https://media.retroachievements.org/Images/059289.png', 'https://media.retroachievements.org/Images/011925.png', 'https://media.retroachievements.org/Images/077248.png', 'https://media.retroachievements.org/Images/077249.png', 4.3),
  (56, 10509, '~Hack~ Super Mario 64: Randomizer', 'Nintendo 64', 2, 980, 980, 980, 34, 0, '3D Platforming, Collect-a-thon', 'ArthurTilly, JoshDuMan, Hacker - Kaze Emanuar, nim', NULL, '2019-03-29', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/117531.png', 'https://media.retroachievements.org/Images/093710.png', 'https://media.retroachievements.org/Images/093707.png', 'https://media.retroachievements.org/Images/093708.png', 4.3),
  (57, 12733, '~Hack~ Super Mario 64: Last Impact', 'Nintendo 64', 2, 973, 973, 973, 57, 0, '3D Platforming', 'Hacker - Kaze Emanuar', 'Hack - Super Mario 64', '2016-09-30', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/069710.png', 'https://media.retroachievements.org/Images/018306.png', 'https://media.retroachievements.org/Images/039419.png', 'https://media.retroachievements.org/Images/017467.png', 4.3),
  (58, 10115, 'Mega Man 64', 'Nintendo 64', 2, 972, 972, 972, 61, 0, 'Action-Adventure, Third-Person Shooter', 'Capcom', 'Capcom', '2001-01-10', 'Mega Man Legends is a 1997 action-adventure game released by Capcom. It is the first game in the Mega Man Legends sub-series of Mega Man games from Capcom, and the second major 3D polygonal Mega Man title in the franchise, following Mega Man: Battle & Chase. It was released for the PlayStation in 1997 in Japan, and in 1998 in North America. A Nintendo 64 port was released in 2000 with the same title, but it was renamed Mega Man 64 for the North American release in 2001. It was also ported to Windows in 2001, and to the PlayStation Portable in 2005, the latter only in Japan. Its most recent release was as a PS one Classic on the North American PlayStation Network in 2015.', 'https://media.retroachievements.org/Images/010690.png', 'https://media.retroachievements.org/Images/010689.png', 'https://media.retroachievements.org/Images/010687.png', 'https://media.retroachievements.org/Images/010688.png', 4.3),
  (59, 10559, '~Hack~ The Legend of Banjo-Kazooie: The Jiggies of Time', 'Nintendo 64', 2, 935, 935, 935, 37, 0, '3D Platforming, Collect-a-thon', 'Hacker - Kurko Mods', 'Hack - Banjo-Kazooie', '2020-07-23', 'Banjo-Kazooie is a 1998 platform game developed by Rare and published by Nintendo for the Nintendo 64. Controlling the player characters, the bear Banjo and the bird Kazooie, the player attempts to save Banjo''s kidnapped sister Tooty from the witch Gruntilda. The player explores nine nonlinear worlds to gather items and progress. Using Banjo and Kazooie''s traversal and combat abilities, they complete challenges such as solving puzzles, jumping over obstacles, and defeating bosses.', 'https://media.retroachievements.org/Images/112578.png', 'https://media.retroachievements.org/Images/035827.png', 'https://media.retroachievements.org/Images/035819.png', 'https://media.retroachievements.org/Images/035823.png', 4.3),
  (60, 10118, 'Toy Story 2: Buzz Lightyear to the Rescue!', 'Nintendo 64', 2, 933, 933, 933, 63, 0, '3D Platforming, Collect-a-thon', NULL, 'Activision', '1999-11-30', 'Toy Story 2: Buzz Lightyear to the Rescue is a 1999 platform game developed by Traveller''s Tales and published by Activision and Disney Interactive. Based on Disney/Pixar''s 1999 computer animated film Toy Story 2, it was released for the Nintendo 64, PlayStation, Microsoft Windows, and Macintosh in late 1999, while a Dreamcast version followed in 2000. The computer versions were released under the title Disney/Pixar''s Action Game, Toy Story 2. A different version, a side-scrolling platform game titled Toy Story 2, was also released for the Game Boy Color in 1999.', 'https://media.retroachievements.org/Images/103350.png', 'https://media.retroachievements.org/Images/049037.png', 'https://media.retroachievements.org/Images/019557.png', 'https://media.retroachievements.org/Images/019556.png', 4.3),
  (61, 10285, 'Bomberman Hero', 'Nintendo 64', 2, 920, 920, 920, 43, 0, '3D Platforming, Action', 'AI', 'Hudson Soft, Nintendo', '1998-04-30', 'Bomberman Hero is a platform video game developed by A.I Co., Ltd. and published by Hudson Soft for the Nintendo 64. It is the second Bomberman game to be released on the system, following Bomberman 64 (1997). It is notable for being a dramatic deviation from previous Bomberman titles, featuring predominant platforming gameplay as opposed to the series'' traditional top-down strategy gameplay.', 'https://media.retroachievements.org/Images/074332.png', 'https://media.retroachievements.org/Images/011147.png', 'https://media.retroachievements.org/Images/011148.png', 'https://media.retroachievements.org/Images/011146.png', 4.3),
  (62, 10182, 'Turok: Dinosaur Hunter', 'Nintendo 64', 2, 899, 899, 899, 52, 0, 'First-Person Shooter', 'Iguana Entertainment', 'Acclaim', '1997-02-28', 'Turok: Dinosaur Hunter is a first-person shooter video game developed by Iguana Entertainment and published by Acclaim Entertainment. It was released in 1997 in North America and Europe for the Nintendo 64 and Microsoft Windows, and is an adaptation of the Valiant Comics comic book series of the same name. The player controls Turok, a Native American warrior who must stop the evil Campaigner from conquering the universe with an ancient and powerful weapon.', 'https://media.retroachievements.org/Images/020130.png', 'https://media.retroachievements.org/Images/011072.png', 'https://media.retroachievements.org/Images/011068.png', 'https://media.retroachievements.org/Images/011075.png', 4.3),
  (63, 10337, 'Spider-Man', 'Nintendo 64', 2, 894, 894, 894, 37, 0, '3D Platforming, Beat ''em Up', 'Edge of Reality', 'Activision', '2000-11-21', 'Spider-Man is a superhero in American comic books published by Marvel Comics. Created by writer-editor Stan Lee and artist Steve Ditko, he first appeared in the anthology comic book Amazing Fantasy #15 in the Silver Age of Comic Books. Widely regarded as one of the most popular and commercially successful superheroes, he has been featured in comic books, television shows, films, video games, novels, and plays.', 'https://media.retroachievements.org/Images/107338.png', 'https://media.retroachievements.org/Images/012410.png', 'https://media.retroachievements.org/Images/019554.png', 'https://media.retroachievements.org/Images/019555.png', 4.3),
  (64, 10136, '1080° Snowboarding', 'Nintendo 64', 2, 886, 886, 886, 39, 0, 'Extreme Sports - Snowboarding', NULL, 'Nintendo', '1998-03-31', '1080° Snowboarding is a snowboarding video game developed and published by Nintendo for the Nintendo 64 in 1998. In the game, players control one of five snowboarders from a third-person perspective, using a combination of buttons to jump and perform tricks across eight levels.', 'https://media.retroachievements.org/Images/011233.png', 'https://media.retroachievements.org/Images/034964.png', 'https://media.retroachievements.org/Images/011234.png', 'https://media.retroachievements.org/Images/011235.png', 4.3),
  (65, 10129, 'Fighting Force 64', 'Nintendo 64', 2, 884, 884, 884, 90, 0, 'Beat ''em Up', 'Core Design', 'Crave Entertainment', '1999-04-30', 'Fighting Force is a beat ''em up video game developed by Core Design and published in 1997 by Eidos Interactive for PlayStation and Windows. A Nintendo 64 version was published by Crave Entertainment in 1999. The Japanese version for the PlayStation was published by Electronic Arts Victor. Announced by Core shortly after the success of Tomb Raider, Fighting Force was highly anticipated but met with mixed reviews. It was followed by Fighting Force 2.', 'https://media.retroachievements.org/Images/063155.png', 'https://media.retroachievements.org/Images/014507.png', 'https://media.retroachievements.org/Images/011045.png', 'https://media.retroachievements.org/Images/011046.png', 4.3),
  (66, 10124, 'Tony Hawk''s Pro Skater', 'Nintendo 64', 2, 872, 872, 872, 35, 0, 'Extreme Sports - Skateboarding', 'Edge of Reality', 'Activision', '2000-02-01', 'Tony Hawk''s Pro Skater, released as Tony Hawk''s Skateboarding in the United Kingdom, Australia, New Zealand, and parts of Europe, is a 1999 skateboarding video game developed by Neversoft and published by Activision. It is the first installment in the Tony Hawk''s series. It was released for the PlayStation on September 29, 1999 and was later ported to the Nintendo 64, Game Boy Color, Dreamcast, and N-Gage.', 'https://media.retroachievements.org/Images/115224.png', 'https://media.retroachievements.org/Images/071343.png', 'https://media.retroachievements.org/Images/017042.png', 'https://media.retroachievements.org/Images/017044.png', 4.3),
  (67, 16504, '~Hack~ The Legend of Zelda: The Missing Link', 'Nintendo 64', 2, 871, 871, 871, 16, 0, 'Action-Adventure', 'Hacker - Kaze Emanuar, CDi-Falls, Zel', 'Hack - The Legend of Zelda: Ocarina of Time', '2020-07-25', 'The Legend of Zelda is a video game series created by Japanese game designers Shigeru Miyamoto and Takashi Tezuka. It is primarily developed and published by Nintendo, but some installments and re-releases have been outsourced to Flagship, Grezzo, and Tantalus Media.', 'https://media.retroachievements.org/Images/036028.png', 'https://media.retroachievements.org/Images/036009.png', 'https://media.retroachievements.org/Images/035982.png', 'https://media.retroachievements.org/Images/036010.png', 4.3),
  (68, 10269, 'Rayman 2: The Great Escape', 'Nintendo 64', 2, 863, 863, 863, 49, 0, '3D Platforming, Collect-a-thon', 'Ubisoft', 'Ubisoft', '1999-11-06', 'Rayman 2: The Great Escape is a 1999 platform game developed by Ubi Pictures and published by Ubi Soft for the Nintendo 64, Windows, Dreamcast and PlayStation. The game centers on the titular character Rayman, who is tasked with saving the fantastical land of the Fairy Glade from an army of robotic pirates led by Admiral Razorbeard.', 'https://media.retroachievements.org/Images/064754.png', 'https://media.retroachievements.org/Images/014327.png', 'https://media.retroachievements.org/Images/091524.png', 'https://media.retroachievements.org/Images/091523.png', 4.3),
  (69, 17494, '~Hack~ Banjo-Kazooie: Nostalgia 64', 'Nintendo 64', 2, 838, 838, 838, 48, 0, '3D Platforming, Collect-a-thon', 'Hacker - Kurko Mods', 'Hack - Banjo-Kazooie', '2025-05-16', 'Banjo-Kazooie is a 1998 platform game developed by Rare and published by Nintendo for the Nintendo 64. Controlling the player characters, the bear Banjo and the bird Kazooie, the player attempts to save Banjo''s kidnapped sister Tooty from the witch Gruntilda. The player explores nine nonlinear worlds to gather items and progress. Using Banjo and Kazooie''s traversal and combat abilities, they complete challenges such as solving puzzles, jumping over obstacles, and defeating bosses.', 'https://media.retroachievements.org/Images/112116.png', 'https://media.retroachievements.org/Images/112226.png', 'https://media.retroachievements.org/Images/111802.png', 'https://media.retroachievements.org/Images/111803.png', 4.3),
  (70, 10347, 'Quake 64', 'Nintendo 64', 2, 814, 814, 814, 95, 0, 'First-Person Shooter', 'Midway Studios', 'Midway', '1998-03-24', 'Quake is a 1996 first-person shooter video game developed by id Software and published by GT Interactive. The first game in the Quake series, it was originally released for MS-DOS and Windows, followed by Classic Mac OS, Linux, and Saturn in 1997 and Nintendo 64 in 1998.', 'https://media.retroachievements.org/Images/020238.png', 'https://media.retroachievements.org/Images/036508.png', 'https://media.retroachievements.org/Images/036506.png', 'https://media.retroachievements.org/Images/036507.png', 4.3),
  (71, 10216, 'Quest 64', 'Nintendo 64', 2, 807, 807, 807, 32, 0, 'Turn-Based RPG', 'Imagineer', 'THQ', '1998-06-01', 'Quest 64 is a role-playing video game (RPG) developed by Imagineer for the Nintendo 64. It was released in North America in June 1998 by THQ, Europe in September 1998 by Konami and Japan in July 1999 by Imagineer. It is the first role-playing video game released for the system in North America.', 'https://media.retroachievements.org/Images/066089.png', 'https://media.retroachievements.org/Images/014514.png', 'https://media.retroachievements.org/Images/011871.png', 'https://media.retroachievements.org/Images/011872.png', 4.3),
  (72, 10168, 'LEGO Racers', 'Nintendo 64', 2, 800, 800, 800, 53, 0, 'Kart Racing', 'High Voltage Software', 'LEGO Interactive | LEGO Media', '1999-10-12', 'Lego Racers is a 1999 Lego-themed kart racing video game developed by High Voltage Software and published by Lego Media for Microsoft Windows, followed by console ports to Nintendo 64 and PlayStation. Set in the fictional "Legoland" universe, the single-player mode follows various minifigure characters competing in a racing competition created by a fictional racing champion called Rocket Racer.', 'https://media.retroachievements.org/Images/063603.png', 'https://media.retroachievements.org/Images/010796.png', 'https://media.retroachievements.org/Images/010794.png', 'https://media.retroachievements.org/Images/010795.png', 4.3),
  (73, 10685, 'Sesame Street: Elmo''s Letter Adventure', 'Nintendo 64', 2, 800, 800, 800, 16, 0, 'Educational', 'Realtime Associates', 'NewKidCo', '1999-11-15', ' There have been a variety of Sesame Street video games released for video game platforms. Most of the Sesame Street video games were published and developed by NewKidCo.', 'https://media.retroachievements.org/Images/116921.png', 'https://media.retroachievements.org/Images/047409.png', 'https://media.retroachievements.org/Images/042796.png', 'https://media.retroachievements.org/Images/045349.png', 4.3),
  (74, 20279, '~Hack~ The Preservation Project', 'Nintendo 64', 2, 792, 792, 792, 8, 0, NULL, 'Fluvian, MarioNova', 'Hack - Super Mario 64', '2022-06-08', ' The Nintendo 64 is a video game console released by Nintendo in 1996. The console was a moderate success with 32.93 millions units sold; it was three times as much as one competitor, the Sega Saturn, but only a third of the sales of its other competitor, the original PlayStation. Third party game developers cancelled multiple games for the system, with commonly-cited reasons including its lower sales numbers compared to the PlayStation, its unconventional controller, and Nintendo''s decision to stick with the game cartridge format, which was more costly to produce and featured far less storage than the PlayStation''s CD-ROMs. Additionally, the brief lifespan and commercial failure of the 64DD, a Japan-only Nintendo 64 add-on, led to many of its games being cancelled, reworked for release on the standard Nintendo 64, or ported to its successor, the GameCube. This list documents games that were announced for the Nintendo 64 at some point, but did not end up being released for it in any capacity. It also documents cancelled 64DD games, as well as unreleased 64DD-specific versions of other Nintendo 64 games.', 'https://media.retroachievements.org/Images/121472.png', 'https://media.retroachievements.org/Images/067966.png', 'https://media.retroachievements.org/Images/067968.png', 'https://media.retroachievements.org/Images/067969.png', 4.3),
  (75, 14897, '~Hack~ Super Mario 64: Splitscreen Multiplayer', 'Nintendo 64', 2, 776, 776, 776, 29, 0, '3D Platforming, Collect-a-thon', 'Hacker - Kaze Emanuar', 'Hack - Super Mario 64', '2020-01-16', 'The following is a list of video games that feature cooperative gameplay, either as a primary or secondary gameplay mode.', 'https://media.retroachievements.org/Images/112472.png', 'https://media.retroachievements.org/Images/029212.png', 'https://media.retroachievements.org/Images/029862.png', 'https://media.retroachievements.org/Images/029925.png', 4.2),
  (76, 10198, 'Goemon''s Great Adventure', 'Nintendo 64', 2, 773, 773, 773, 86, 0, '2D Platforming', 'Konami', 'Konami', '1998-12-23', 'Goemon''s Great Adventure, known as Mystical Ninja 2 Starring Goemon in Europe, is a video game developed and released by Konami for the Nintendo 64 on December 23, 1998. It is the fourth game in the Ganbare Goemon series released in North America and Europe, as well as the fourteenth and latest overall mainline installment, following Mystical Ninja Starring Goemon, released two years earlier. Featuring platform gameplay in 2.5D, it returns the series to a side-scrolling format.', 'https://media.retroachievements.org/Images/047181.png', 'https://media.retroachievements.org/Images/011156.png', 'https://media.retroachievements.org/Images/011149.png', 'https://media.retroachievements.org/Images/011152.png', 4.2),
  (77, 10186, 'Ridge Racer 64', 'Nintendo 64', 2, 744, 744, 744, 40, 0, 'Arcade Racing', 'Namco', 'Nintendo', '2000-02-01', 'Ridge Racer 64 is a 2000 racing video game developed by Nintendo Software Technology and published by Nintendo for the Nintendo 64. It is the first title of Namco''s Ridge Racer series to not be on arcades or a PlayStation console, with Namco licensing the series to Nintendo to develop the game. In 2004, the game was remade for the Nintendo DS as Ridge Racer DS, which uses the system''s features such as the touch-screen and wireless multi-player. Additionally, Gina Cavalli from R: Racing Evolution replaced Reiko Nagase as the mascot in the DS version. The N64 version received its first official re-release on the Nintendo Classics service on January 31, 2025; followed by a Japanese release in May 16, 2025.', 'https://media.retroachievements.org/Images/115803.png', 'https://media.retroachievements.org/Images/015092.png', 'https://media.retroachievements.org/Images/017050.png', 'https://media.retroachievements.org/Images/017051.png', 4.2),
  (78, 11569, '~Hack~ Super Mario 64: Chaos Edition', 'Nintendo 64', 2, 737, 737, 737, 117, 0, '3D Platforming', NULL, 'Hack - Super Mario 64', '2020-09-27', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/111702.png', 'https://media.retroachievements.org/Images/038525.png', 'https://media.retroachievements.org/Images/038524.png', 'https://media.retroachievements.org/Images/038523.png', 4.2),
  (79, 10159, 'Castlevania: Legacy of Darkness', 'Nintendo 64', 2, 732, 732, 732, 43, 0, 'Action-Adventure, 3D Platforming', 'Konami', 'Konami', '1999-11-30', 'Castlevania: Legacy of Darkness is a 1999 action-adventure game developed and published by Konami for the Nintendo 64. A prequel and expanded version of Castlevania, also released on the Nintendo 64 earlier the same year, it contains a revision of the original game with improved graphics, added villains, and alternate versions of some levels.', 'https://media.retroachievements.org/Images/091412.png', 'https://media.retroachievements.org/Images/071793.png', 'https://media.retroachievements.org/Images/071794.png', 'https://media.retroachievements.org/Images/071795.png', 4.2),
  (80, 10326, 'Bust-A-Move ''99', 'Nintendo 64', 2, 728, 728, 728, 143, 0, NULL, 'Taito', 'Acclaim', '1999-04-30', 'Puzzle Bobble 3 is an action puzzle video game developed by Taito. The second sequel to Puzzle Bobble, it was released for arcades in September 1996 and later ported to the Sega Saturn, PlayStation, Game Boy, Nintendo 64 and Microsoft Windows. Like its predecessors, the player is tasked with shooting balls at groups of balls, creating groups of three or more, which are then removed from play. Further ports for the Nintendo Switch, PlayStation 4 and Xbox One were released in February 2023 by City Connection alongside Puzzle Bobble 2.', 'https://media.retroachievements.org/Images/097072.png', 'https://media.retroachievements.org/Images/012269.png', 'https://media.retroachievements.org/Images/011931.png', 'https://media.retroachievements.org/Images/011932.png', 4.2),
  (81, 10170, 'Beetle Adventure Racing!', 'Nintendo 64', 2, 717, 717, 717, 37, 0, 'Arcade Racing', 'Paradigm Entertainment, Electronic Arts', 'Electronic Arts', '1999-01-01', 'Beetle Adventure Racing! is a racing game released for the Nintendo 64 in 1999. It was developed by Paradigm Entertainment and EA Canada, and published by Electronic Arts. Each vehicle in the game is a Volkswagen New Beetle, which was released the previous year. The gameplay involves racing other players on unlocked tracks, finding and destroying crates, and collecting colored ladybugs while battling other players. The single-player championship offers three circuits and a secret bonus circuit with new vehicles and tracks available upon completion.', 'https://media.retroachievements.org/Images/000000.png', 'https://media.retroachievements.org/Images/066421.png', 'https://media.retroachievements.org/Images/010802.png', 'https://media.retroachievements.org/Images/010803.png', 4.2),
  (82, 17312, '~Hack~ Breaking the Barrier', 'Nintendo 64', 2, 709, 709, 709, 13, 0, '3D Platforming', 'Marionova64', 'Hack - Super Mario 64', '2020-08-05', 'The history of video games began in the 1950s and 1960s as computer scientists began designing simple games and simulations on minicomputers and mainframes. Spacewar! was developed by Massachusetts Institute of Technology (MIT) student hobbyists in 1962 as one of the first such games on a video display. The first consumer video game hardware was released in the early 1970s. The first home video game console was the Magnavox Odyssey, and the first arcade video games were Computer Space and Pong. After its home console conversions, numerous companies sprang up to capture Pong''s success in both the arcade and the home by cloning the game, causing a series of boom and bust cycles due to oversaturation and lack of innovation.', 'https://media.retroachievements.org/Images/040841.png', 'https://media.retroachievements.org/Images/045649.png', 'https://media.retroachievements.org/Images/040838.png', 'https://media.retroachievements.org/Images/040839.png', 4.2),
  (83, 22859, 'Clay Fighter 63 1/3', 'Nintendo 64', 2, 680, 680, 680, 38, 0, '3D Fighting', 'Interplay Entertainment', 'Interplay Entertainment', '1997-10-21', 'ClayFighter 63⅓ is a 1997 fighting game developed and published by Interplay Productions for the Nintendo 64. It is the third installment in the ClayFighter series. The title is a parody of the 64 suffix common in Nintendo 64 games, and a reference to Naked Gun 33 1/3.', 'https://media.retroachievements.org/Images/072015.png', 'https://media.retroachievements.org/Images/071834.png', 'https://media.retroachievements.org/Images/071832.png', 'https://media.retroachievements.org/Images/071833.png', 4.2),
  (84, 10457, 'Cruis''n Exotica', 'Nintendo 64', 2, 680, 680, 680, 102, 0, 'Arcade Racing', 'Gratuitous Games', 'Midway', '2000-10-16', 'Cruis''n Exotica is a 1999 racing game developed and published by Midway Games for arcades. The game is a sequel to Cruis''n World and is the third entry in Nintendo''s Cruis''n series. A port to the Nintendo 64 developed by Gratuitous Games was released in 2000, along with a Game Boy Color version developed by Crawfish Interactive.', 'https://media.retroachievements.org/Images/054763.png', 'https://media.retroachievements.org/Images/054293.png', 'https://media.retroachievements.org/Images/054291.png', 'https://media.retroachievements.org/Images/054292.png', 4.2),
  (85, 10586, 'Clay Fighter: Sculptor''s Cut', 'Nintendo 64', 2, 674, 674, 674, 44, 0, '3D Fighting', 'Interplay Entertainment', 'Interplay Entertainment', '1998-05-15', 'ClayFighter 63⅓ is a 1997 fighting game developed and published by Interplay Productions for the Nintendo 64. It is the third installment in the ClayFighter series. The title is a parody of the 64 suffix common in Nintendo 64 games, and a reference to Naked Gun 33 1/3.', 'https://media.retroachievements.org/Images/069062.png', 'https://media.retroachievements.org/Images/047500.png', 'https://media.retroachievements.org/Images/069056.png', 'https://media.retroachievements.org/Images/069057.png', 4.2),
  (86, 10459, 'Sesame Street: Elmo''s Number Journey', 'Nintendo 64', 2, 672, 672, 672, 18, 0, 'Educational', 'Realtime Associates', 'NewKidCo', '1999-11-30', ' There have been a variety of Sesame Street video games released for video game platforms. Most of the Sesame Street video games were published and developed by NewKidCo.', 'https://media.retroachievements.org/Images/115204.png', 'https://media.retroachievements.org/Images/042079.png', 'https://media.retroachievements.org/Images/045281.png', 'https://media.retroachievements.org/Images/067494.png', 4.2),
  (87, 10271, 'Re-Volt', 'Nintendo 64', 2, 665, 665, 665, 144, 0, 'Kart Racing', 'Acclaim', 'Acclaim', '1999-07-31', 'Re-Volt is a 1999 racing video game designed by Paul Phippen and Simon Harrison. It was developed by Acclaim Studios London and published by Acclaim Entertainment for Microsoft Windows, Nintendo 64, PlayStation and Dreamcast.', 'https://media.retroachievements.org/Images/124206.png', 'https://media.retroachievements.org/Images/024510.png', 'https://media.retroachievements.org/Images/024511.png', 'https://media.retroachievements.org/Images/024512.png', 4.2),
  (88, 14658, '~Hack~ Super Mario 64 Land', 'Nintendo 64', 2, 662, 662, 662, 97, 0, '3D Platforming', 'Hacker - Kaze Emanuar', 'Hack - Super Mario 64', '2019-11-11', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/027511.png', 'https://media.retroachievements.org/Images/029595.png', 'https://media.retroachievements.org/Images/027803.png', 'https://media.retroachievements.org/Images/027818.png', 4.2),
  (89, 32649, '~Hack~ Mario in the Multiverse', 'Nintendo 64', 2, 648, 648, 648, 56, 0, '3D Platforming, Collect-a-thon', 'rovertronic', 'Hack - Super Mario 64', '2024-12-24', 'Eternal Darkness: Sanity''s Requiem is a 2002 survival horror game developed by Silicon Knights and published by Nintendo for the GameCube. It was produced and directed by Denis Dyack. The game follows the story of several characters across a period of two millennia and four different locations on Earth, as they contend with an ancient evil who seeks to enslave humanity. The gameplay distinguishes itself with unique "sanity effects", visual and audial effects that confuse the player and often break the fourth wall.', 'https://media.retroachievements.org/Images/105955.png', 'https://media.retroachievements.org/Images/105954.png', 'https://media.retroachievements.org/Images/105951.png', 'https://media.retroachievements.org/Images/105952.png', 4.2),
  (90, 10119, 'Sin and Punishment', 'Nintendo 64', 2, 625, 625, 625, 74, 0, 'Rail Shooter', 'Treasure', 'Nintendo', '2000-11-21', 'Sin and Punishment is a rail shooter video game co-developed by Treasure and Nintendo for the Nintendo 64, and released in Japan in 2000. Its story takes place in the near future of 2007 when war breaks out as humanity is struggling with a global famine. The player takes on the roles of Saki and Airan as they fight to save Earth from destruction. The game employs a unique scheme that uses both the D-pad and control stick on the Nintendo 64 controller, allowing players to maneuver the character while simultaneously aiming the targeting reticle. To progress the game, the player must shoot at enemies and projectiles while dodging attacks to survive.', 'https://media.retroachievements.org/Images/093936.png', 'https://media.retroachievements.org/Images/065251.png', 'https://media.retroachievements.org/Images/015875.png', 'https://media.retroachievements.org/Images/015876.png', 4.2),
  (91, 10407, 'Buck Bumble', 'Nintendo 64', 2, 622, 622, 622, 55, 0, NULL, 'Argonaut Games', 'Ubisoft', '1998-11-18', 'Buck Bumble is a 1998 third-person shooter video game developed by Argonaut Software and published by UbiSoft for the Nintendo 64. A special Buck Bumble rumble pack was packaged with the UK version. The game''s premise centers around anthropomorphic insects that were created as a result of a chemical spill in London, which are split into two factions at war.', 'https://media.retroachievements.org/Images/036016.png', 'https://media.retroachievements.org/Images/046370.png', 'https://media.retroachievements.org/Images/036017.png', 'https://media.retroachievements.org/Images/036018.png', 4.2),
  (92, 10114, 'Mortal Kombat Trilogy', 'Nintendo 64', 2, 619, 619, 619, 45, 0, '2D Fighting', 'Midway', 'Williams Entertainment', '1996-11-01', 'Mortal Kombat Trilogy is a 1996 fighting game released by Midway as the second and final update to Mortal Kombat 3 for the PlayStation, Nintendo 64, Sega Saturn and PCs. Further versions were also released for the Game.com and R-Zone. It features a similar basic gameplay system and the same story as Ultimate Mortal Kombat 3, but adds characters and stages restored from Mortal Kombat and Mortal Kombat II. New additions to the game included the "Aggressor" bar and the Brutality mechanic. The game was met with mixed to positive reviews upon release.', 'https://media.retroachievements.org/Images/019539.png', 'https://media.retroachievements.org/Images/010683.png', 'https://media.retroachievements.org/Images/017832.png', 'https://media.retroachievements.org/Images/017833.png', 4.2),
  (93, 14671, '~Hack~ Paper Mario: Black Pit', 'Nintendo 64', 2, 617, 617, 617, 82, 0, 'Turn-Based RPG', 'elDexter', 'Hack - Paper Mario', '2021-07-11', 'Mario Party is a series of party video games created by Hudson Soft and owned by Nintendo. It features characters from the Mario franchise in which up to four local players or computer-controlled characters compete in a board game interspersed with minigames. Designed by Shigeru Miyamoto, and directed by Kenji Kikuchi, the games are currently developed by Nintendo Cube and published by Nintendo, being previously developed by Hudson Soft. The series is known for its party game elements, including the often unpredictable multiplayer game modes that allow play with up to four, and sometimes eight, human players or CPUs.', 'https://media.retroachievements.org/Images/045967.png', 'https://media.retroachievements.org/Images/068171.png', 'https://media.retroachievements.org/Images/045585.png', 'https://media.retroachievements.org/Images/045587.png', 4.2),
  (94, 14157, '~Hack~ Waluigi''s Taco Stand', 'Nintendo 64', 2, 616, 616, 616, 10, 0, '3D Platforming', 'Hacker - Kaze Emanuar', 'Hack - Super Mario 64', '2018-08-12', NULL, 'https://media.retroachievements.org/Images/024242.png', 'https://media.retroachievements.org/Images/025120.png', 'https://media.retroachievements.org/Images/024240.png', 'https://media.retroachievements.org/Images/025121.png', 4.2),
  (95, 17582, '~Hack~ Super Mario 64: Sonic Edition Plus', 'Nintendo 64', 2, 593, 593, 593, 71, 0, '3D Platforming, Collect-a-thon', 'Gamebun', 'Hack - Super Mario 64', '2021-05-01', 'The Super Nintendo Entertainment System, known in Japan as the Super Famicom (SFC), is a home video game console developed and marketed by Nintendo. It was released in Japan on November 21, 1990, in North America on August 23, 1991, and internationally throughout 1992. It was Nintendo''s second programmable home console, following the Nintendo Entertainment System (NES). A fourth-generation console, the SNES primarily competed with Sega''s Genesis in the console war, a fierce battle for market share in the United States and Europe.', 'https://media.retroachievements.org/Images/104136.png', 'https://media.retroachievements.org/Images/101856.png', 'https://media.retroachievements.org/Images/043422.png', 'https://media.retroachievements.org/Images/043423.png', 4.2),
  (96, 10158, 'Destruction Derby 64', 'Nintendo 64', 2, 587, 587, 587, 44, 0, 'Vehicular Combat', 'Looking Glass Studios', 'THQ', '1999-09-30', 'Destruction Derby 64 is a vehicular combat racing video game developed by Looking Glass Studios and published by THQ, under license from Psygnosis. It is the third installment in the Destruction Derby series, released on 30 September 1999 in North America and 12 October 1999 in Europe for the Nintendo 64.', 'https://media.retroachievements.org/Images/010834.png', 'https://media.retroachievements.org/Images/014504.png', 'https://media.retroachievements.org/Images/010770.png', 'https://media.retroachievements.org/Images/010771.png', 4.2),
  (97, 17838, '~Hack~ All Bosses', 'Nintendo 64', 2, 577, 577, 577, 12, 0, '3D Platforming', 'Hacker - Kaze Emanuar', 'Hack - Super Mario 64', '2020-11-25', 'Banjo-Kazooie is a 1998 platform game developed by Rare and published by Nintendo for the Nintendo 64. Controlling the player characters, the bear Banjo and the bird Kazooie, the player attempts to save Banjo''s kidnapped sister Tooty from the witch Gruntilda. The player explores nine nonlinear worlds to gather items and progress. Using Banjo and Kazooie''s traversal and combat abilities, they complete challenges such as solving puzzles, jumping over obstacles, and defeating bosses.', 'https://media.retroachievements.org/Images/070137.png', 'https://media.retroachievements.org/Images/051334.png', 'https://media.retroachievements.org/Images/045636.png', 'https://media.retroachievements.org/Images/045637.png', 4.2),
  (98, 10272, 'StarCraft 64', 'Nintendo 64', 2, 565, 565, 565, 76, 0, 'Real-Time Strategy', 'Blizzard Entertainment', 'Blizzard Entertainment', '2000-06-12', 'StarCraft is a real-time strategy video game developed and published by Blizzard Entertainment for Microsoft Windows. The first installment of the video game series of the same name, it was released in 1998. A Classic Mac OS version was released in 1999, and a Nintendo 64 port co-developed with Mass Media and published by Nintendo was released in 2000.', 'https://media.retroachievements.org/Images/051791.png', 'https://media.retroachievements.org/Images/014423.png', 'https://media.retroachievements.org/Images/014360.png', 'https://media.retroachievements.org/Images/014424.png', 4.2),
  (99, 29579, '~Hack~ SM64: Decades Later', 'Nintendo 64', 2, 563, 563, 563, 99, 0, '3D Platforming', 'Hacker - BroDute, aglab2', 'Hack - Super Mario 64', '2024-03-29', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/098021.png', 'https://media.retroachievements.org/Images/097971.png', 'https://media.retroachievements.org/Images/097731.png', 'https://media.retroachievements.org/Images/097732.png', 4.2),
  (100, 10137, 'A Bug''s Life', 'Nintendo 64', 2, 562, 562, 562, 84, 0, '3D Platforming', 'Traveller''s Tales', 'Activision', '1999-04-30', 'A Bug''s Life is a 1998 American animated comedy film produced by Pixar Animation Studios for Walt Disney Pictures. It was directed by John Lasseter, written by Andrew Stanton, Donald McEnery, and Bob Shaw, from a story conceived by Lasseter, Stanton, and Joe Ranft, and stars the voices of Dave Foley, Kevin Spacey, Julia Louis-Dreyfus, and Hayden Panettiere. In the film, a misfit anthropomorphic ant named Flik looks for "tough warriors" to save his ant colony from a protection racket run by a gang of grasshoppers. However, the "warriors" he brings back are a troupe of Circus Bugs. The film''s plot was initially inspired by Aesop''s fable The Ant and the Grasshopper.', 'https://media.retroachievements.org/Images/067485.png', 'https://media.retroachievements.org/Images/058191.png', 'https://media.retroachievements.org/Images/058226.png', 'https://media.retroachievements.org/Images/058225.png', 4.2),
  (101, 10489, 'Namco Museum 64', 'Nintendo 64', 2, 556, 556, 556, 64, 0, 'Compilation, Arcade', 'Mass Media', 'Namco', '1999-11-29', 'Namco Museum is a series of video game compilations developed and published by Bandai Namco Entertainment for home video game consoles. The first title in the series, Namco Museum Vol. 1, was released for the PlayStation in 1995. Entries in the series have been released for multiple platforms, including the Game Boy Advance, PlayStation 2, PlayStation Portable, Nintendo DS and Xbox 360. the latest being Namco Museum Archives Vol. 2, released in 2020.', 'https://media.retroachievements.org/Images/072246.png', 'https://media.retroachievements.org/Images/018291.png', 'https://media.retroachievements.org/Images/018834.png', 'https://media.retroachievements.org/Images/018835.png', 4.2),
  (102, 10394, 'Ms. Pac-Man Maze Madness', 'Nintendo 64', 2, 555, 555, 555, 40, 0, 'Collect-a-thon, Maze Chase', 'Mass Media', 'Namco', '2000-11-12', 'Ms. Pac-Man Maze Madness is a 2000 maze video game developed and published by Namco Hometek for the PlayStation. It was later released for the Nintendo 64, Dreamcast, and Game Boy Advance. A remake of General Computer Corporation''s Ms. Pac-Man (1982), players control the titular character in her quest to stop a witch named Mesmerelda from stealing the Gems of Virtue. The game was well-received upon release, with critics applauding its simplicity and faithfulness to the arcade original. A sequel was in development around 2006 but was cancelled for unknown reasons.', 'https://media.retroachievements.org/Images/065894.png', 'https://media.retroachievements.org/Images/065944.png', 'https://media.retroachievements.org/Images/024915.png', 'https://media.retroachievements.org/Images/024916.png', 4.2),
  (103, 12767, '~Hack~ Super Mario 64: Ocarina of Time', 'Nintendo 64', 2, 554, 554, 554, 39, 0, '3D Platforming, Collect-a-thon', 'Hacker - Kaze Emanuar', 'Hack - Super Mario 64', '2018-03-26', 'Mario Kart 64 is a 1996 kart racing game for the Nintendo 64 (N64). Developed and published by Nintendo, it is the second installment in the Mario Kart series after 1992''s Super Mario Kart. The game retains the gameplay of its predecessor: the player, controlling a Mario franchise character, races opponents around tracks based on locales from the Super Mario platform games. Tracks contain obstacles to slow the player down and item boxes which give the player power-ups to aid in their progress. Mario Kart 64 contains different single-player and local multiplayer game modes, including a Grand Prix racing mode and a last man standing battle mode.', 'https://media.retroachievements.org/Images/112585.png', 'https://media.retroachievements.org/Images/042736.png', 'https://media.retroachievements.org/Images/016779.png', 'https://media.retroachievements.org/Images/016865.png', 4.2),
  (104, 10452, 'Bio F.R.E.A.K.S.', 'Nintendo 64', 2, 544, 544, 544, 47, 0, '3D Fighting', 'Midway', 'Midway', '1998-05-19', 'Bio F.R.E.A.K.S. is a 3D fighting video game released by Midway in 1998. It was originally planned for arcades. Prototypes of the game were tested at arcades, but the final arcade release was canceled and the game was later released for the PlayStation, Nintendo 64 and Microsoft Windows.', 'https://media.retroachievements.org/Images/064331.png', 'https://media.retroachievements.org/Images/067721.png', 'https://media.retroachievements.org/Images/067720.png', 'https://media.retroachievements.org/Images/067719.png', 4.2),
  (105, 17700, '~Hack~ Mario Party 64', 'Nintendo 64', 2, 515, 515, 515, 20, 0, '3D Platforming', 'MrComit', 'Hack - Super Mario 64', '2020-02-16', 'Mario Party is a 1998 party video game developed by Hudson Soft and published by Nintendo for the Nintendo 64. The game was targeted at a young audience. Mario creator Shigeru Miyamoto served as development supervisor. The game was released in Japan on December 18, 1998, North America on February 8, 1999, and in PAL regions on March 9, 1999. It received mostly positive critical reviews for its multiplayer mode, concept, and music; disapproval of its slow pacing; and mixed reviews of its graphics. It is the first installment in the Mario Party series and was followed by Mario Party 2 in 1999. The game received its first official re-release on the Nintendo Classics service in 2022. Content from this game was remastered as part of Mario Party: The Top 100 for the Nintendo 3DS, Mario Party Superstars and Super Mario Party Jamboree for the Nintendo Switch.', 'https://media.retroachievements.org/Images/044563.png', 'https://media.retroachievements.org/Images/045838.png', 'https://media.retroachievements.org/Images/044366.png', 'https://media.retroachievements.org/Images/044367.png', 4.2),
  (106, 10683, 'Hybrid Heaven', 'Nintendo 64', 2, 512, 512, 512, 99, 0, 'Action RPG', 'Konami', 'Konami', '1999-09-01', 'Hybrid Heaven is a 1999 action role playing game developed by Konami Computer Entertainment Osaka and published by Konami for Nintendo 64. This game is most notable for its peculiar mix of genres: it has aspects of both role-playing video games and action-adventure games. It is also one of the few Nintendo 64 titles to support a widescreen mode.', 'https://media.retroachievements.org/Images/020806.png', 'https://media.retroachievements.org/Images/066798.png', 'https://media.retroachievements.org/Images/066799.png', 'https://media.retroachievements.org/Images/066865.png', 4.2),
  (107, 12732, '~Hack~ Super Mario 64: Sapphire', 'Nintendo 64', 2, 502, 502, 502, 13, 0, '3D Platforming', 'Nebula', 'Hack - Super Mario 64', '2017-12-10', 'Nintendo has developed eight home video game consoles and multiple portable consoles for use with external media, as well as dedicated consoles and other hardware for their consoles. As of September 19, 2025, Nintendo has sold over 869.95 million hardware units.', 'https://media.retroachievements.org/Images/025042.png', 'https://media.retroachievements.org/Images/023484.png', 'https://media.retroachievements.org/Images/023485.png', 'https://media.retroachievements.org/Images/023486.png', 4.2),
  (108, 10646, 'Scooby-Doo! Classic Creep Capers', 'Nintendo 64', 2, 498, 498, 498, 20, 0, 'Adventure', 'TerraGlyph Interactive Studios', 'THQ', '2000-11-30', 'Scooby-Doo! Classic Creep Capers is an adventure game published by THQ for the Nintendo 64 and Game Boy Color, based on the Hanna-Barbera cartoon Scooby-Doo, Where Are You!. The Nintendo 64 version, developed by Terraglyph Interactive Studios, was released in November 2000, while the Game Boy Color version was developed by Digital Eclipse Software, and released in February 2001. A PlayStation version, identical to the Nintendo 64 version, had been in development by Terraglyph Interactive Studios but was later cancelled.', 'https://media.retroachievements.org/Images/082474.png', 'https://media.retroachievements.org/Images/023155.png', 'https://media.retroachievements.org/Images/023156.png', 'https://media.retroachievements.org/Images/023157.png', 4.2),
  (109, 13831, '~Hack~ Super Mario Bros. 64', 'Nintendo 64', 2, 475, 475, 475, 40, 0, '3D Platforming', 'Hacker - Kaze Emanuar', 'Hack - Super Mario 64', '2018-12-21', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/067928.png', 'https://media.retroachievements.org/Images/022410.png', 'https://media.retroachievements.org/Images/069194.png', 'https://media.retroachievements.org/Images/069125.png', 4.2),
  (110, 10172, 'Tetrisphere', 'Nintendo 64', 2, 455, 455, 455, 39, 0, NULL, 'H2O Interactive', 'Nintendo', '1997-08-11', 'Tetrisphere is a puzzle video game developed by H2O Entertainment and published by Nintendo for the Nintendo 64. It was released in North America on August 11, 1997, and in PAL regions in February 1998. The game, originally titled Phear, was initially intended for release on the Atari Jaguar in early 1995 but was reworked into a Tetris game for the N64 after Nintendo, a licensee for The Tetris Company, obtained the publishing rights.', 'https://media.retroachievements.org/Images/060090.png', 'https://media.retroachievements.org/Images/052884.png', 'https://media.retroachievements.org/Images/052882.png', 'https://media.retroachievements.org/Images/052883.png', 4.2),
  (111, 33246, '~Hack~ BAZR', 'Nintendo 64', 2, 454, 454, 454, 61, 0, '3D Platforming, Roguelike', 'anonymous_moose, furyiousfight, spk', 'Hack - Super Mario 64', '2025-02-11', 'The Lega Calcio Serie A, commonly known as Lega Serie A, is the league that runs the major professional football competitions in Italy, most prominently the Serie A; the top division of Italian football.', 'https://media.retroachievements.org/Images/111634.png', 'https://media.retroachievements.org/Images/115414.png', 'https://media.retroachievements.org/Images/109782.png', 'https://media.retroachievements.org/Images/111545.png', 4.2),
  (112, 22000, '~Hack~ Chao Bandstand', 'Nintendo 64', 2, 447, 447, 447, 15, 0, '3D Platforming', 'Gamebun', NULL, '2021-08-05', 'La Femme Nikita is a Canadian action-drama television series based on the French film of the same name by Luc Besson. The series stars Peta Wilson as the titular character. It was co-produced by Jay Firestone of Fireworks Entertainment and Warner Bros. Domestic Television Distribution. It was created and adapted for television by Joel Surnow and Robert Cochran. The series was telecast in the United States on the USA Network cable channel on Monday, January 13, 1997 at 10pm, and ran for five seasons until March 4, 2001. The series was also aired in Canada on the over-the-air CTV Television Network. La Femme Nikita was the highest-rated drama on American basic cable during its first two seasons. It was also distributed in some other countries.', 'https://media.retroachievements.org/Images/066224.png', 'https://media.retroachievements.org/Images/066319.png', 'https://media.retroachievements.org/Images/066125.png', 'https://media.retroachievements.org/Images/066126.png', 4.1),
  (113, 23761, '~Hack~ The Legend of Zelda: The Sealed Palace', 'Nintendo 64', 2, 442, 442, 442, 100, 0, 'Action-Adventure', 'Jinnosuke, Shoopey, Col0Korn', 'Hack - The Legend of Zelda: Ocarina of Time', '2023-03-23', 'Nintendo is a Japanese multinational video game company headquartered in Kyoto. It develops, publishes, and manufactures both video games and video game consoles. The history of Nintendo began in 1889 when craftsman Fusajiro Yamauchi founded the company to produce handmade hanafuda playing cards. After venturing into various lines of business and becoming a public company, Nintendo began producing toys in the 1960s, and later video games.', 'https://media.retroachievements.org/Images/071750.png', 'https://media.retroachievements.org/Images/091011.png', 'https://media.retroachievements.org/Images/071723.png', 'https://media.retroachievements.org/Images/071724.png', 4.1),
  (114, 10614, 'Shadowgate 64: Trials of the Four Towers', 'Nintendo 64', 2, 442, 442, 442, 42, 0, 'Adventure', 'Infinite Ventures', 'Kemco', '1999-06-09', 'Shadowgate 64: Trials of the Four Towers, also known simply as Shadowgate 64, is a 1999 adventure game developed by TNS Co., Ltd. and Infinite Ventures and published by Kemco for Nintendo 64. It is a sequel to the original Shadowgate.', 'https://media.retroachievements.org/Images/037093.png', 'https://media.retroachievements.org/Images/033044.png', 'https://media.retroachievements.org/Images/033042.png', 'https://media.retroachievements.org/Images/033043.png', 4.1),
  (115, 10392, 'South Park Rally', 'Nintendo 64', 2, 434, 434, 434, 61, 0, 'Kart Racing', 'Tantalus Interactive', 'Acclaim', '2000-03-01', 'South Park Rally is a kart-style racing video game released in early 2000 based on the American animated sitcom South Park published by Acclaim Entertainment and released for the PlayStation, Microsoft Windows, Nintendo 64, and Dreamcast. Gameplay follows the player in a competitive racing championship set in the fictional town of South Park. Players are given the options for multiplayer, arcade, or championship modes, but only the championship unlocks extra features. Competition begins in South Park''s 1st Rally, a circuit race around four checkpoints in the downtown area of South Park. Races get gradually more diverse, with more locations, racers, and elements added as the game progresses.', 'https://media.retroachievements.org/Images/071842.png', 'https://media.retroachievements.org/Images/016564.png', 'https://media.retroachievements.org/Images/016562.png', 'https://media.retroachievements.org/Images/016563.png', 4.1),
  (116, 10121, 'Duke Nukem 64', 'Nintendo 64', 2, 430, 430, 430, 132, 0, 'First-Person Shooter', 'Apogee Software | 3D Realms, Eurocom', 'Atari', '1997-11-14', 'Duke Nukem 3D is a 1996 first-person shooter game developed by 3D Realms and published by FormGen for MS-DOS. It is a sequel to the platform games Duke Nukem and Duke Nukem II, published by 3D Realms.', 'https://media.retroachievements.org/Images/020240.png', 'https://media.retroachievements.org/Images/098495.png', 'https://media.retroachievements.org/Images/010775.png', 'https://media.retroachievements.org/Images/010895.png', 4.1),
  (117, 17367, '~Hack~ Roblox 64', 'Nintendo 64', 2, 422, 422, 422, 7, 0, '3D Platforming', 'SwiftySky', 'Hack - Super Mario 64', '2018-08-22', 'The video game industry in the United States is one of the fastest-growing entertainment industries in the country. The American video game industry is the largest video game industry in the world. According to a 2020 study released by the Entertainment Software Association (ESA), the yearly economic output of the American video game industry in 2019 was $90.3 billion, supporting over 429,000 American jobs. With an average yearly salary of about $121,000, the latter figure includes over 143,000 individuals who are directly employed by the video game business. Additionally, activities connected to the video game business generate $12.6 billion in federal, state, and local taxes each year. The World Economic Forum estimates that, by 2025, the American gaming industry will reach $42.3 billion while the worldwide gaming industry will possibly reach US$270 billion. The United States is one of the nations with the largest influence in the video game industry, with video games representing a significant part of its economy.', 'https://media.retroachievements.org/Images/041148.png', 'https://media.retroachievements.org/Images/051326.png', 'https://media.retroachievements.org/Images/041142.png', 'https://media.retroachievements.org/Images/041147.png', 4.1),
  (118, 25613, '~Hack~ SM64: Beyond the Cursed Mirror', 'Nintendo 64', 2, 422, 422, 422, 78, 0, NULL, 'rovertronic', NULL, '2023-05-05', NULL, 'https://media.retroachievements.org/Images/081966.png', 'https://media.retroachievements.org/Images/084189.png', 'https://media.retroachievements.org/Images/084190.png', 'https://media.retroachievements.org/Images/084191.png', 4.1),
  (119, 17812, '~Hack~ Mario and the Mystic Purple Stars', 'Nintendo 64', 2, 420, 420, 420, 28, 0, '3D Platforming, Collect-a-thon', 'Progji', 'Hack - Super Mario 64', '2020-11-19', 'The following is a comprehensive index of all games released in 2025, sorted chronologically by release date, and divided by quarter. Information regarding developer, publisher, operating system, genre and type of release is provided where available', 'https://media.retroachievements.org/Images/048694.png', 'https://media.retroachievements.org/Images/056054.png', 'https://media.retroachievements.org/Images/048727.png', 'https://media.retroachievements.org/Images/045451.png', 4.1),
  (120, 19551, '~Hack~ Super Mario 64: Through the Ages', 'Nintendo 64', 2, 419, 419, 419, 68, 0, NULL, NULL, 'Hack - Super Mario 64', '2022-04-30', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/104561.png', 'https://media.retroachievements.org/Images/059039.png', 'https://media.retroachievements.org/Images/057647.png', 'https://media.retroachievements.org/Images/057646.png', 4.1),
  (121, 10607, 'Chameleon Twist', 'Nintendo 64', 2, 410, 410, 410, 32, 0, '3D Platforming', 'Japan System Supply', 'Sunsoft', '1997-11-30', 'Chameleon Twist is a 1997 video game developed by Japan System Supply, published by Japan System Supply in Japan, and published by Sunsoft in North America and Europe for the Nintendo 64.', 'https://media.retroachievements.org/Images/029672.png', 'https://media.retroachievements.org/Images/015027.png', 'https://media.retroachievements.org/Images/015028.png', 'https://media.retroachievements.org/Images/015058.png', 4.1),
  (122, 10530, 'WCW vs. nWo: World Tour', 'Nintendo 64', 2, 407, 407, 407, 31, 0, 'Sports - Wrestling', 'Asmik Ace Entertainment, AKI Corporation', 'THQ', '1997-11-01', 'WCW vs. nWo: World Tour is a professional wrestling video game released in 1997 for the Nintendo 64 game console. Released at the peak of World Championship Wrestling''s (WCW) dominance in the Monday Night War, World Tour was THQ''s first foray into the N64 wrestling scene and is a semi-sequel to the lesser known WCW vs. the World for the PlayStation. It is the second best-selling wrestling game for the N64 console.', 'https://media.retroachievements.org/Images/015111.png', 'https://media.retroachievements.org/Images/015110.png', 'https://media.retroachievements.org/Images/015068.png', 'https://media.retroachievements.org/Images/044134.png', 4.1),
  (123, 10627, 'South Park: Chef''s Luv Shack', 'Nintendo 64', 2, 404, 404, 404, 75, 0, 'Trivia, Party', 'Acclaim', 'Acclaim', '1999-10-12', 'South Park: Chef''s Luv Shack is a 2D game show-style party video game and is a sequel to the 1998 video game South Park, itself based on the American animated sitcom of the same name. Developed by Acclaim Studios Austin and published by Acclaim Entertainment, it was released in 1999 for the Dreamcast, Microsoft Windows, PlayStation and Nintendo 64. Its gameplay involves minigames and the ability to play against other players in a challenge for the most points. It also involves trivia questions about South Park and other topics.', 'https://media.retroachievements.org/Images/071670.png', 'https://media.retroachievements.org/Images/057196.png', 'https://media.retroachievements.org/Images/057194.png', 'https://media.retroachievements.org/Images/057195.png', 4.1),
  (124, 10171, 'Tetris 64', 'Nintendo 64', 2, 401, 401, 401, 40, 0, 'Falling Block Puzzle', 'Amtex', 'SETA', '1998-11-13', 'Tetris 64 is a 1998 puzzle video game developed by Amtex and published by SETA for the Nintendo 64. Released exclusively in Japan, it came packaged with the "Bio Sensor", a unique accessory which alters the gameplay based on the player''s heart rate.', 'https://media.retroachievements.org/Images/098365.png', 'https://media.retroachievements.org/Images/025506.png', 'https://media.retroachievements.org/Images/025503.png', 'https://media.retroachievements.org/Images/025504.png', 4.1),
  (125, 14447, '~Hack~ Super Mario 64: The Green Comet', 'Nintendo 64', 2, 400, 400, 400, 32, 0, '3D Platforming', 'Arthurtilly', 'Hack - Super Mario 64', '2019-01-14', 'Paper Mario is a video game series and part of the Mario franchise, developed by Intelligent Systems and published by Nintendo. It combines elements from the role-playing, action-adventure, and puzzle genres. Players control a paper cutout version of Mario, usually with allies, on a quest to defeat the antagonist. The series consists of six games and one spin-off; the first, Paper Mario (2000), was released for the Nintendo 64, and the most recent, a 2024 remake of 2004''s Paper Mario: The Thousand-Year Door, for the Nintendo Switch.', 'https://media.retroachievements.org/Images/047936.png', 'https://media.retroachievements.org/Images/047671.png', 'https://media.retroachievements.org/Images/047627.png', 'https://media.retroachievements.org/Images/047629.png', 4.1),
  (126, 13113, 'Puyo Puyo Sun 64', 'Nintendo 64', 2, 398, 398, 398, 29, 0, NULL, 'Compile', 'Compile', '1997-10-31', 'Puyo Puyo Sun  is the third installment of the Puyo Puyo series, and the sequel to Puyo Puyo 2, made in 1996 by Compile. After the highly acclaimed success of its predecessor, Compile took a slightly more retro approach, so players had a more original feel to the game over that of 2.', 'https://media.retroachievements.org/Images/121321.png', 'https://media.retroachievements.org/Images/056034.png', 'https://media.retroachievements.org/Images/018984.png', 'https://media.retroachievements.org/Images/018985.png', 4.1),
  (127, 11647, '~Hack~ Super Mario 64: The Green Stars', 'Nintendo 64', 2, 388, 388, 388, 54, 0, NULL, 'Kampel125', 'Hack - Super Mario 64', '2013-07-21', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/052022.png', 'https://media.retroachievements.org/Images/026852.png', 'https://media.retroachievements.org/Images/023255.png', 'https://media.retroachievements.org/Images/023256.png', 4.1),
  (128, 10127, 'Duke Nukem: Zero Hour', 'Nintendo 64', 2, 386, 386, 386, 106, 0, 'Third-Person Shooter', 'Eurocom', 'GT Interactive Software', '1999-08-01', 'Duke Nukem: Zero Hour is a 1999 third-person shooter game in the Duke Nukem series, developed by Eurocom and published by GT Interactive for the Nintendo 64. The game uses a relatively large 32 megabyte cartridge and can also use the Expansion Pak to improve graphics, though this slows down the frame rate. It features a 4-player split-screen multiplayer mode that uses a first-person view.', 'https://media.retroachievements.org/Images/066261.png', 'https://media.retroachievements.org/Images/011039.png', 'https://media.retroachievements.org/Images/011035.png', 'https://media.retroachievements.org/Images/068219.png', 4.1),
  (129, 10223, 'Gex 3: Deep Cover Gecko', 'Nintendo 64', 2, 383, 383, 383, 55, 0, '3D Platforming, Collect-a-thon', 'Gratuitous Games', 'Crave Entertainment', '1999-09-28', 'Gex 3: Deep Cover Gecko is a 1999 platform game developed by Crystal Dynamics and published by Eidos Interactive for the PlayStation. It is part of the Gex video game series, and was released in 1999, followed by ports for the Nintendo 64. Its protagonist, Gex, is a wisecracking, pop culture enthusiast voiced by Danny John-Jules in the UK and European releases and comedian Dana Gould, reprising his role from former Gex games, for the American release. The gameplay is set in Gex''s secret hideout, Mission Control a overworld, which is overseen by Gex''s butler, Alfred the Turtle. Playboy model Marliece Andrada plays Gex''s kidnapped companion, Agent Xtra, the only live-action character, who is featured in brief full-motion video sequences on the PlayStation version. The plot follows Gex''s return to the Media Dimension to rescue Agent Xtra from Rez, Gex''s arch-nemesis from the previous games.', 'https://media.retroachievements.org/Images/109678.png', 'https://media.retroachievements.org/Images/014508.png', 'https://media.retroachievements.org/Images/010964.png', 'https://media.retroachievements.org/Images/010962.png', 4.1),
  (130, 25610, '~Hack~ Paper Mario: TTYD64', 'Nintendo 64', 2, 381, 381, 381, 208, 0, 'Turn-Based RPG', 'elDexter', 'Hack - Paper Mario', '2023-08-13', NULL, 'https://media.retroachievements.org/Images/083844.png', 'https://media.retroachievements.org/Images/085911.png', 'https://media.retroachievements.org/Images/085912.png', 'https://media.retroachievements.org/Images/085913.png', 4.1),
  (131, 22459, '~Hack~ The Quest For Milk 64', 'Nintendo 64', 2, 379, 379, 379, 9, 0, '3D Platforming', 'Deathray9000', 'Hack - Super Mario 64', '2022-09-07', 'Conker''s Bad Fur Day is a 2001 platform game developed by Rare and published by Rare in North America and by THQ in Europe for the Nintendo 64. The game follows Conker, a greedy, hard-drinking red squirrel who must return home to his girlfriend, Berri, after an evening of heavily drinking at the local pub. Most of the game requires the player to complete a linear sequence of challenges that involve jumping over obstacles, solving puzzles, and fighting enemies. A multiplayer mode in which up to four players can compete against each other in seven different game types is also included. It is the second installment in the Conker series, after Conker''s Pocket Tales (1999).', 'https://media.retroachievements.org/Images/114410.png', 'https://media.retroachievements.org/Images/068397.png', 'https://media.retroachievements.org/Images/068394.png', 'https://media.retroachievements.org/Images/068396.png', 4.1),
  (132, 29843, '~Hack~ The Legend of Zelda: Ultimate Trial', 'Nintendo 64', 2, 377, 377, 377, 81, 0, NULL, 'Ultimate Trial''s Team', NULL, '2024-05-24', 'Link is a character and the protagonist of Nintendo''s video game franchise The Legend of Zelda. He was created by Japanese video game designer Shigeru Miyamoto. Link was introduced as the hero of the original The Legend of Zelda video game in 1986 and has appeared in a total of 21 entries in the series, as well as a number of spin-offs. Common elements in the series include Link travelling through Hyrule whilst exploring dungeons, battling creatures, and solving puzzles until he eventually defeats the series'' primary antagonist, Ganon, and saves Princess Zelda.', 'https://media.retroachievements.org/Images/097877.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/097736.png', 'https://media.retroachievements.org/Images/097786.png', 4.1),
  (133, 10587, 'Monopoly', 'Nintendo 64', 2, 377, 377, 377, 16, 0, 'Board Game', 'Mind''s Eye Productions', 'Hasbro Interactive', '1999-12-18', 'A monopoly is a market in which one person or company is the only supplier of a particular good or service. A monopoly is characterized by a lack of economic competition to produce a particular thing, a lack of viable substitute goods, and the possibility of a high monopoly price well above the seller''s marginal cost that leads to a high monopoly profit. The verb monopolise or monopolize refers to the process by which a company gains the ability to raise prices or exclude competitors. In economics, a monopoly is a single seller. In law, a monopoly is a business entity that has significant market power, that is, the power to charge overly high prices, which is associated with unfair price raises. Although monopolies may be big businesses, size is not a characteristic of a monopoly. A small business may still have the power to raise prices in a small industry.', 'https://media.retroachievements.org/Images/078339.png', 'https://media.retroachievements.org/Images/017514.png', 'https://media.retroachievements.org/Images/017515.png', 'https://media.retroachievements.org/Images/017517.png', 4.1),
  (134, 27401, '~Homebrew~ Portal 64', 'Nintendo 64', 2, 375, 375, 375, 25, 0, 'Action, Puzzle', 'lambertjamesd', 'lambertjamesd', '2023-01-01', 'Mario Kart 64 is a 1996 kart racing game for the Nintendo 64 (N64). Developed and published by Nintendo, it is the second installment in the Mario Kart series after 1992''s Super Mario Kart. The game retains the gameplay of its predecessor: the player, controlling a Mario franchise character, races opponents around tracks based on locales from the Super Mario platform games. Tracks contain obstacles to slow the player down and item boxes which give the player power-ups to aid in their progress. Mario Kart 64 contains different single-player and local multiplayer game modes, including a Grand Prix racing mode and a last man standing battle mode.', 'https://media.retroachievements.org/Images/109991.png', 'https://media.retroachievements.org/Images/086166.png', 'https://media.retroachievements.org/Images/086164.png', 'https://media.retroachievements.org/Images/086165.png', 4.1),
  (135, 17507, '~Hack~ Kirby 64: Whispy''s Trials', 'Nintendo 64', 2, 374, 374, 374, 12, 0, '2.5D Platforming', 'jesusyoshi54', 'Hack - Kirby 64 - The Crystal Shards', '2020-10-04', NULL, 'https://media.retroachievements.org/Images/124333.png', 'https://media.retroachievements.org/Images/113748.png', 'https://media.retroachievements.org/Images/052714.png', 'https://media.retroachievements.org/Images/098039.png', 4.1),
  (136, 10255, 'Shadow Man', 'Nintendo 64', 2, 373, 373, 373, 74, 0, 'Action, Survival Horror', 'Acclaim', 'Acclaim', '1999-07-31', 'Shadow Man is a 1999 action-adventure video game developed by Acclaim Studios Teesside and published by Acclaim Entertainment. It is based on the Shadow Man comic book series published by Valiant Comics. The game was released for Nintendo 64, Microsoft Windows, and PlayStation on August 31, 1999, with a Dreamcast version following on December 1.', 'https://media.retroachievements.org/Images/055462.png', 'https://media.retroachievements.org/Images/012742.png', 'https://media.retroachievements.org/Images/012746.png', 'https://media.retroachievements.org/Images/012747.png', 4.1),
  (137, 27596, '~Hack~ Wario''s Hint Art', 'Nintendo 64', 2, 368, 368, 368, 51, 0, '3D Platforming', 'Lawnmowerman', 'Hack - Super Mario 64', '2022-11-21', 'Wario Land 3, known in Japan as Wario Land 3: Mysterious Music Box, is a 2000 platform game developed by Nintendo R&D1 and published by Nintendo for the Game Boy Color. The game''s plot centers around Wario who must free a mysterious figure who is trapped inside a music box. The game was released in Japan on March 21, 2000, Europe on April 14, 2000, and North America on May 30, 2000.', 'https://media.retroachievements.org/Images/106495.png', 'https://media.retroachievements.org/Images/106190.png', 'https://media.retroachievements.org/Images/100000.png', 'https://media.retroachievements.org/Images/100001.png', 4.1),
  (138, 10429, 'Fighters Destiny', 'Nintendo 64', 2, 365, 365, 365, 75, 0, '3D Fighting', 'Opus, Anchor', 'Imagineer, Ocean', '1998-01-26', 'Fighters Destiny, known in Japan as Fighting Cup, is a 1998 video game developed by Genki alongside Opus Corp and Anchor Inc for the Nintendo 64. It closely models the 3D fighting game standards of the time but integrates a unique point scoring system. The game''s generic characters and unoriginal presentation have been panned by critics, but reviewers praised its point system and consider it to be one of the best fighting games on the Nintendo 64. It was followed by a sequel, Fighter Destiny 2, released in 2000.', 'https://media.retroachievements.org/Images/120787.png', 'https://media.retroachievements.org/Images/066556.png', 'https://media.retroachievements.org/Images/080486.png', 'https://media.retroachievements.org/Images/080487.png', 4.1),
  (139, 34305, '~Hack~ Mario Breaks EVERY BONE IN HIS BODY', 'Nintendo 64', 2, 364, 364, 364, 7, 0, '3D Platforming', 'CowQuack', 'Hack - Super Mario 64', '2024-03-27', 'The 1990s was the third decade in the industry''s history. It was a decade of marked innovation in video gaming. It was a decade of transition from sprite-based graphics to full-fledged 3D graphics and it gave rise to several genres of video games including, but not limited to, the first-person shooter, real-time strategy, survival horror, and MMO. Arcade games, although still very popular in the early 1990s, began to decline as home consoles became more common. The fourth, fifth and sixth generation of video game consoles went on sale, including the Sega Genesis, Super Nintendo, Sega Saturn, PlayStation, Nintendo 64, Game Boy Color and the Sega Dreamcast. Notable games released in the 1990s included Super Mario World, Sonic the Hedgehog, Street Fighter II, Mortal Kombat, Doom, Wolfenstein 3D, Quake, Final Fantasy VII, Half-Life, Super Mario 64, Pokémon Red, Blue, and Yellow, GoldenEye 007, The Legend of Zelda: Ocarina of Time, Super Metroid, Castlevania: Symphony of the Night, Metal Gear Solid, Resident Evil, StarCraft, Tomb Raider, Gran Turismo, Super Mario Kart, Crash Bandicoot, Spyro the Dragon, Tony Hawk''s Pro Skater, Age of Empires, Civilization, Myst, and Soulcalibur.', 'https://media.retroachievements.org/Images/115448.png', 'https://media.retroachievements.org/Images/115453.png', 'https://media.retroachievements.org/Images/115450.png', 'https://media.retroachievements.org/Images/115451.png', 4.1),
  (140, 10330, 'Bomberman 64: The Second Attack!', 'Nintendo 64', 2, 361, 361, 361, 50, 0, 'Action, Puzzle', 'Hudson Soft', 'Vatical Entertainment', '1999-12-03', 'Bomberman 64: The Second Attack! is a 1999 action video game, the sequel to 1997''s Bomberman 64.', 'https://media.retroachievements.org/Images/111878.png', 'https://media.retroachievements.org/Images/111789.png', 'https://media.retroachievements.org/Images/036034.png', 'https://media.retroachievements.org/Images/036033.png', 4.1),
  (141, 10517, 'Top Gear Rally', 'Nintendo 64', 2, 359, 359, 359, 52, 0, 'Rally Racing', 'Boss Game Studios', 'Midway', '1997-01-01', 'Top Gear Rally is a 1997 racing video game developed by Boss Game Studios and released for the Nintendo 64. A follow-up to Kemco''s original Top Gear game, it features a championship mode where a single player must complete six seasons of two to four races, as well as a multiplayer mode where two players may compete against each other via a split-screen display. The game''s tracks combine both road and off-road surfaces and can be played in different weather conditions, including night, fog, rain, and snow. Players may customize their car with different tire grips and adjust its suspension stiffness and steering sensitivity. An option that allows players to custom paint their cars is also included.', 'https://media.retroachievements.org/Images/055460.png', 'https://media.retroachievements.org/Images/017964.png', 'https://media.retroachievements.org/Images/017965.png', 'https://media.retroachievements.org/Images/017963.png', 4.1),
  (142, 10486, 'Mission: Impossible', 'Nintendo 64', 2, 358, 358, 358, 37, 0, 'Action-Adventure', 'Infogrames', 'Ocean Software', '1998-01-01', 'Mission: Impossible is an American multimedia franchise based on a fictional secret espionage agency known as the Impossible Missions Force (IMF). The 1966 TV series ran for seven seasons and was revived in 1988 for two seasons. It inspired a series of theatrical motion pictures starring Tom Cruise beginning in 1996.', 'https://media.retroachievements.org/Images/077322.png', 'https://media.retroachievements.org/Images/046537.png', 'https://media.retroachievements.org/Images/034941.png', 'https://media.retroachievements.org/Images/034939.png', 4.1),
  (143, 10515, 'Tom and Jerry in Fists of Furry', 'Nintendo 64', 2, 356, 356, 356, 36, 0, 'Arena Fighting', 'VIS Entertainment', 'Ubisoft, NewKidCo', '2000-11-12', 'Tom and Jerry in Fists of Furry is a fighting video game for the Nintendo 64 and Microsoft Windows. It was developed by VIS Interactive and published by NewKidCo on November 12, 2000. It is based on the animated short film series of Tom and Jerry.', 'https://media.retroachievements.org/Images/026284.png', 'https://media.retroachievements.org/Images/018274.png', 'https://media.retroachievements.org/Images/026283.png', 'https://media.retroachievements.org/Images/018273.png', 4.1),
  (144, 14486, '~Hack~ Zelda 64: Dawn & Dusk', 'Nintendo 64', 2, 344, 344, 344, 15, 0, 'Action-Adventure', 'Captain Seedy-Eye', 'Hack - The Legend of Zelda: Ocarina of Time', '2019-09-23', 'Nintendo is a Japanese multinational video game company headquartered in Kyoto. It develops, publishes, and manufactures both video games and video game consoles. The history of Nintendo began in 1889 when craftsman Fusajiro Yamauchi founded the company to produce handmade hanafuda playing cards. After venturing into various lines of business and becoming a public company, Nintendo began producing toys in the 1960s, and later video games.', 'https://media.retroachievements.org/Images/050121.png', 'https://media.retroachievements.org/Images/049481.png', 'https://media.retroachievements.org/Images/027005.png', 'https://media.retroachievements.org/Images/027004.png', 4.1),
  (145, 18183, '~Hack~ The Legend of Zelda: Ocarina of Time - Spaceworld ''97 BETA Experience', 'Nintendo 64', 2, 340, 340, 340, 16, 0, 'Action-Adventure', 'Zel', 'Hack - The Legend of Zelda: Ocarina of Time', '2021-11-21', 'The 64DD is a peripheral developed by Nintendo to expand the capabilities of the Nintendo 64 with rewritable magnetic disks and online connectivity. Announced in 1995 before the Nintendo 64''s 1996 launch, it faced multiple delays before its release in Japan on December 11, 1999. The "64" references both the Nintendo 64 console and the 64 MB storage capacity of the disks, while "DD" stands for "disk drive" or "dynamic drive". Despite its innovative features, it struggled to gain traction and was discontinued after a short-lived run in Japan.', 'https://media.retroachievements.org/Images/050300.png', 'https://media.retroachievements.org/Images/050291.png', 'https://media.retroachievements.org/Images/050293.png', 'https://media.retroachievements.org/Images/050299.png', 4.1),
  (146, 10149, 'Army Men: Sarge''s Heroes 2', 'Nintendo 64', 2, 336, 336, 336, 59, 0, 'Third-Person Shooter', 'The 3DO Company', 'The 3DO Company', '2000-09-26', 'Army Men: Sarge''s Heroes 2 is a 2000 third-person shooter video game developed and published by The 3DO Company for the Nintendo 64, Game Boy Color, PlayStation, and PlayStation 2. The game is a direct sequel to Army Men: Sarge''s Heroes (1999). Unlike the previous game which was more dark in tone, this game has more of a lighthearted storyline.', 'https://media.retroachievements.org/Images/100395.png', 'https://media.retroachievements.org/Images/010749.png', 'https://media.retroachievements.org/Images/034959.png', 'https://media.retroachievements.org/Images/079537.png', 4.1),
  (147, 22554, '~Hack~ Mario Aimlessly Drives a Car Around the City 64', 'Nintendo 64', 2, 327, 327, 327, 9, 0, NULL, 'CowQuack', 'Hack - Super Mario 64', '2021-04-14', 'Donald Miller was an American serial killer who murdered one woman and later four gay men in Los Angeles County, California, from 1977 to 1981. He was convicted and sentenced to death for four of these killings in 1983, but died awaiting execution in 2005.', 'https://media.retroachievements.org/Images/068443.png', 'https://media.retroachievements.org/Images/104871.png', 'https://media.retroachievements.org/Images/069036.png', 'https://media.retroachievements.org/Images/069035.png', 4.1),
  (148, 17857, '~Hack~ Star Revenge 0: Galaxy of Origins', 'Nintendo 64', 2, 326, 326, 326, 56, 0, '3D Platforming, Collect-a-thon', NULL, 'Hack - Super Mario 64', '2020-08-15', 'Star Wars: Rogue Squadron or Star Wars: Rogue Squadron 3D is an arcade-style flight action game co-developed by Factor 5 and LucasArts. The first of the Rogue Squadron trilogy, it was published by LucasArts and Nintendo and released for Microsoft Windows and Nintendo 64 in December 1998. The game''s story was influenced by the Star Wars: X-wing – Rogue Squadron comics and is set in the fictional Star Wars galaxy, taking place primarily between events in the films Star Wars and The Empire Strikes Back. The player controls Luke Skywalker, commander of the elite X-wing pilots known as Rogue Squadron. As the game progresses, Skywalker and Rogue Squadron fight the Galactic Empire in 16 missions across various planets.', 'https://media.retroachievements.org/Images/083814.png', 'https://media.retroachievements.org/Images/062871.png', 'https://media.retroachievements.org/Images/062869.png', 'https://media.retroachievements.org/Images/062870.png', 4.1),
  (149, 10333, 'San Francisco Rush 2049', 'Nintendo 64', 2, 321, 321, 321, 65, 0, 'Arcade Racing', 'Midway', 'Midway', '2000-09-05', 'San Francisco Rush 2049 is a 1999 racing video game developed and manufactured by Atari Games for arcades, later ported to home systems. It is the third game in the Rush series as the sequel to San Francisco Rush: Extreme Racing and Rush 2: Extreme Racing USA as well as the last to be set in the city of San Francisco. An updated version with fixes and more tracks was later released subtitled Tournament Edition.', 'https://media.retroachievements.org/Images/064758.png', 'https://media.retroachievements.org/Images/044716.png', 'https://media.retroachievements.org/Images/044718.png', 'https://media.retroachievements.org/Images/044717.png', 4.1),
  (150, 14664, '~Hack~ Super Mario and the Cursed Castles', 'Nintendo 64', 2, 320, 320, 320, 58, 0, NULL, 'Foxen', 'Hack - Super Mario 64', '2019-06-06', 'Paper Mario is a video game series and part of the Mario franchise, developed by Intelligent Systems and published by Nintendo. It combines elements from the role-playing, action-adventure, and puzzle genres. Players control a paper cutout version of Mario, usually with allies, on a quest to defeat the antagonist. The series consists of six games and one spin-off; the first, Paper Mario (2000), was released for the Nintendo 64, and the most recent, a 2024 remake of 2004''s Paper Mario: The Thousand-Year Door, for the Nintendo Switch.', 'https://media.retroachievements.org/Images/027589.png', 'https://media.retroachievements.org/Images/027590.png', 'https://media.retroachievements.org/Images/027539.png', 'https://media.retroachievements.org/Images/027541.png', 4.1),
  (151, 19486, '~Hack~ Banjo-Kazooie: Gruntilda''s Mask', 'Nintendo 64', 2, 318, 318, 318, 14, 0, NULL, 'Hacker - Kurko Mods', NULL, '2019-01-01', 'Banjo-Kazooie is a 1998 platform game developed by Rare and published by Nintendo for the Nintendo 64. Controlling the player characters, the bear Banjo and the bird Kazooie, the player attempts to save Banjo''s kidnapped sister Tooty from the witch Gruntilda. The player explores nine nonlinear worlds to gather items and progress. Using Banjo and Kazooie''s traversal and combat abilities, they complete challenges such as solving puzzles, jumping over obstacles, and defeating bosses.', 'https://media.retroachievements.org/Images/061483.png', 'https://media.retroachievements.org/Images/061480.png', 'https://media.retroachievements.org/Images/061484.png', 'https://media.retroachievements.org/Images/061485.png', 4.1),
  (152, 10087, 'Rampage: World Tour', 'Nintendo 64', 2, 309, 309, 309, 33, 0, 'Action, Arcade', 'Saffire', 'Midway', '1998-03-30', 'Rampage World Tour is a 1997 action video game developed by Game Refuge and published by Midway Games for arcades. It is the sequel to 1986''s Rampage, and was designed by Brian Colin and Jeff Nauman, who designed the original game. Ports were released for the PlayStation, Sega Saturn, Nintendo 64, Game Boy Color, and Microsoft Windows. It was re-released on Midway Arcade Treasures 2 and included in Rampage: Total Destruction.', 'https://media.retroachievements.org/Images/072387.png', 'https://media.retroachievements.org/Images/010671.png', 'https://media.retroachievements.org/Images/010668.png', 'https://media.retroachievements.org/Images/010669.png', 4.1),
  (153, 16509, '~Hack~ The Legend of Zelda: Master of Time', 'Nintendo 64', 2, 303, 303, 303, 45, 0, 'Action-Adventure', 'doncamilo', 'Hack - The Legend of Zelda: Ocarina of Time', '2020-07-30', 'The Legend of Zelda: Ocarina of Time is a 1998 action-adventure game developed and published by Nintendo for the Nintendo 64. It was the first Legend of Zelda game with 3D graphics. It was released in Japan and North America in November 1998 and in PAL regions the following month.', 'https://media.retroachievements.org/Images/040364.png', 'https://media.retroachievements.org/Images/036149.png', 'https://media.retroachievements.org/Images/040363.png', 'https://media.retroachievements.org/Images/040365.png', 4.1),
  (154, 10532, 'Wipeout 64', 'Nintendo 64', 2, 300, 300, 300, 50, 0, 'Racing', 'Psygnosis | Studio Liverpool', 'Midway', '1998-01-01', 'Wipeout 64 is a 1998 racing video game developed by Psygnosis and published by Midway Games for the Nintendo 64. It is the third game in the Wipeout series and remains the only one published on a Nintendo console. At the time of the game''s release, developer Psygnosis had been owned for five years by Sony Computer Entertainment, for whose hardware all subsequent Wipeout games have been released exclusively.', 'https://media.retroachievements.org/Images/052007.png', 'https://media.retroachievements.org/Images/018263.png', 'https://media.retroachievements.org/Images/052005.png', 'https://media.retroachievements.org/Images/052006.png', 4.1),
  (155, 23760, '~Hack~ The Magical Lands', 'Nintendo 64', 2, 293, 293, 293, 32, 0, NULL, 'Papra Mayro 46', NULL, '2023-02-02', 'Glover is a 1998 puzzle-platformer developed by Interactive Studios and published by Hasbro Interactive for the Nintendo 64 and Windows in 1998, and for the PlayStation in 1999. The game follows a magical, four-fingered glove named Glover in his quest to restore the Crystal Kingdom by retrieving crystals that were lost.', 'https://media.retroachievements.org/Images/071887.png', 'https://media.retroachievements.org/Images/071121.png', 'https://media.retroachievements.org/Images/071153.png', 'https://media.retroachievements.org/Images/071154.png', 4.1),
  (156, 10926, 'Mortal Kombat Mythologies: Sub-Zero', 'Nintendo 64', 2, 287, 287, 287, 56, 0, 'Action-Adventure, 2D Fighting', 'Midway', 'Midway', '1997-10-01', 'Mortal Kombat Mythologies: Sub-Zero is a 1997 action-adventure game developed and published by Midway for the PlayStation and Nintendo 64. A spin-off of the Mortal Kombat franchise, it is the first installment not to be a fighting game. Set before the first game in the series, it follows Bi-Han, the elder Sub-Zero, in his quest to find Shinnok''s amulet. It also serves as a prequel to Mortal Kombat 4, which was released the same year, introducing characters and story elements that would be used by the fourth main installment. Mythologies is the final game in the series to use digitized actors.', 'https://media.retroachievements.org/Images/036553.png', 'https://media.retroachievements.org/Images/037889.png', 'https://media.retroachievements.org/Images/037890.png', 'https://media.retroachievements.org/Images/038037.png', 4.1),
  (157, 10360, 'San Francisco Rush: Extreme Racing', 'Nintendo 64', 2, 286, 286, 286, 50, 0, 'Arcade Racing', 'Midway', 'Midway', '1997-11-08', 'San Francisco Rush: Extreme Racing is a 1996 racing video game developed and published by Atari Games for arcades. It was ported to home consoles under the Midway label, beginning with the Nintendo 64 in 1997 and the PlayStation and Windows in 1998. An updated version named San Francisco Rush The Rock: Alcatraz Edition was released with more tracks and cars. It was a critical and commercial hit, and became the first in the Rush series, followed by San Francisco Rush 2049 (1999), bounded by the non-arcade Rush 2: Extreme Racing USA (1998).', 'https://media.retroachievements.org/Images/023348.png', 'https://media.retroachievements.org/Images/023345.png', 'https://media.retroachievements.org/Images/023346.png', 'https://media.retroachievements.org/Images/023347.png', 4.1),
  (158, 25317, '~Hack~ Only Up! 64', 'Nintendo 64', 2, 281, 281, 281, 25, 0, NULL, NULL, NULL, '2023-10-30', 'WWF WrestleMania 2000 is a professional wrestling video game released in 1999 on the Nintendo 64 (N64) console. It was based on the World Wrestling Federation''s annual pay-per-view, WrestleMania. Despite the fact that this game is based upon WrestleMania 2000, the game was released five months prior to the actual PPV itself, therefore resulting in the game using the stage design from the 1999 event, WrestleMania XV, instead. Released at the height of the WWF''s Attitude Era, WrestleMania 2000 was the first WWF game released by THQ. The WWF ended its long relationship with Acclaim Entertainment after witnessing the video game success of its competitor, World Championship Wrestling (WCW), on behalf of THQ. WrestleMania 2000 shares its game engine with the Japan-only release Virtual Pro Wrestling 2: Ōdō Keishō.', 'https://media.retroachievements.org/Images/079526.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/079523.png', 'https://media.retroachievements.org/Images/079524.png', 4.1),
  (159, 17468, '~Hack~ Mario''s Vacation Course', 'Nintendo 64', 2, 280, 280, 280, 8, 0, '3D Platforming', 'Renou', 'Hack - Super Mario 64', '2021-04-16', 'Super Mario is a platform game series developed and published by Nintendo and starring their mascot, Mario. The series was created by Japanese game designer Shigeru Miyamoto and is the flagship series of the greater Mario franchise. At least one Super Mario game has been released for every major Nintendo video game console. A limited number of Super Mario games have also released on non-Nintendo gaming platforms.', 'https://media.retroachievements.org/Images/074071.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/071199.png', 'https://media.retroachievements.org/Images/071200.png', 4.1),
  (160, 10307, 'Space Station Silicon Valley', 'Nintendo 64', 2, 280, 280, 280, 68, 0, '3D Platforming', 'Rockstar North', 'Take-Two Interactive', '1998-10-21', 'Space Station Silicon Valley is a platform video game developed by DMA Design and published by Take-Two Interactive. It was originally released for the Nintendo 64 in October 1998. An adaptation of the game for Game Boy Color was developed by Tarantula Studios and released in 1999. A PlayStation port, developed by Runecraft, was released in 2000, under the name Evo''s Space Adventures. Players control Evo, a robot reduced to a crawling microchip after a ship crash, and are tasked with taking control of animals to solve puzzles and defeat enemies.', 'https://media.retroachievements.org/Images/113172.png', 'https://media.retroachievements.org/Images/066072.png', 'https://media.retroachievements.org/Images/011372.png', 'https://media.retroachievements.org/Images/011371.png', 4.1),
  (161, 20051, '~Hack~ Gourmet Guy''s 1000 IQ Food Quiz', 'Nintendo 64', 2, 277, 277, 277, 8, 0, 'Turn-Based RPG', 'Wrymouth', 'Hack - Paper Mario', '2022-06-18', '   The Japanese children''s manga series Doraemon was written and illustrated by Fujiko F. Fujio. In December 1969, it was serialized in various children''s manga magazines published by Shogakukan.', 'https://media.retroachievements.org/Images/059727.png', 'https://media.retroachievements.org/Images/059733.png', 'https://media.retroachievements.org/Images/059730.png', 'https://media.retroachievements.org/Images/059732.png', 4.1),
  (162, 10265, 'Body Harvest', 'Nintendo 64', 2, 277, 277, 277, 65, 0, 'Action-Adventure, Third-Person Shooter', 'Rockstar North', 'Midway, Gremlin Interactive', '1998-09-30', 'Body Harvest is a 1998 action-adventure video game developed by DMA Design and published by Gremlin Interactive for the Nintendo 64. It was intended to be a launch title for the system, but was delayed due to its original publisher, Nintendo, having issues with the game''s violent themes; they eventually dropped the game, leaving DMA to find a new publisher. Gremlin would later acquire the rights to the game and released it in Europe, while Midway Games released it in North America.', 'https://media.retroachievements.org/Images/051739.png', 'https://media.retroachievements.org/Images/011091.png', 'https://media.retroachievements.org/Images/011089.png', 'https://media.retroachievements.org/Images/011090.png', 4.1),
  (163, 10473, 'Killer Instinct Gold', 'Nintendo 64', 2, 277, 277, 277, 78, 0, '2D Fighting', 'Rare', 'Nintendo', '1996-11-01', 'Killer Instinct Gold is a 1996 fighting game developed by Rare and published by Nintendo for the Nintendo 64. It is based on the arcade game Killer Instinct 2. Players control characters who fight on a 2D plane set against a 3D background. Players press buttons to punch and kick their opponent in chains of successive hits, known as combos. Large combo successions lead to stronger attacks and brutal, stylistic finisher moves underscored by an announcer. Characters—including a gargoyle, a ninja, and a femme fatale—fight in settings such as a jungle and a spaceship. Killer Instinct Gold includes the arcade release''s characters, combos, and 3D, pre-rendered environments, but excludes its full-motion video sequences and some voice-overs due to restrictions of the cartridge media format. The Gold release adds a training mode, camera views, and improved audiovisuals.', 'https://media.retroachievements.org/Images/073831.png', 'https://media.retroachievements.org/Images/080754.png', 'https://media.retroachievements.org/Images/017261.png', 'https://media.retroachievements.org/Images/017262.png', 4.1),
  (164, 14695, '~Hack~ ~Demo~ The Legend of Peach', 'Nintendo 64', 2, 271, 271, 271, 6, 0, NULL, 'Melonspeedruns', NULL, '2021-12-09', 'Princess Peach is a character in Nintendo''s Mario franchise. She was created by Shigeru Miyamoto and introduced in the 1985 original Super Mario Bros. game as Princess Toadstool. She is the princess regnant and head of state of the Mushroom Kingdom, where she resides in her castle along with Toads. Since her debut, she has appeared in the majority of Mario video games as the main female character and the romantic interest of Mario.', 'https://media.retroachievements.org/Images/116456.png', 'https://media.retroachievements.org/Images/111396.png', 'https://media.retroachievements.org/Images/111399.png', 'https://media.retroachievements.org/Images/111400.png', 4.1),
  (165, 19490, '~Hack~ Banjo-Kazooie: How the Gruntch Stole Christmas', 'Nintendo 64', 2, 267, 267, 267, 10, 0, '3D Platforming, Collect-a-thon', 'Hacker - Kurko Mods', 'Hack - Banjo-Kazooie', '2021-12-22', NULL, 'https://media.retroachievements.org/Images/087092.png', 'https://media.retroachievements.org/Images/087061.png', 'https://media.retroachievements.org/Images/087058.png', 'https://media.retroachievements.org/Images/087063.png', 4.1),
  (166, 16760, '~Hack~ Another Mario Adventure', 'Nintendo 64', 2, 263, 263, 263, 69, 0, NULL, 'aglab2 et al.', 'Hack - Super Mario 64', '2020-08-21', 'Paper Mario is a 2000 role-playing video game developed by Intelligent Systems and published by Nintendo for the Nintendo 64 home video game console. Paper Mario is the first game in the Paper Mario series. First released in Japan in 2000 and then internationally in 2001, Paper Mario was later re-released for Nintendo''s Wii Virtual Console in July 2007, the Wii U Virtual Console in April 2015, and the Nintendo Classics service on December 10, 2021.', 'https://media.retroachievements.org/Images/060684.png', 'https://media.retroachievements.org/Images/060566.png', 'https://media.retroachievements.org/Images/060540.png', 'https://media.retroachievements.org/Images/060541.png', 4.1),
  (167, 14036, '~Hack~ Star Revenge 1: Star Takeover', 'Nintendo 64', 2, 263, 263, 263, 36, 0, '3D Platforming', 'Hacker - BroDute', 'Hack - Super Mario 64', '2012-09-03', 'This is a list of video games considered controversial. The list includes games that have earned controversies for violence, sexual content, racism, and review bombing from fans. Some of the video games on this list have been banned or regionally censored.', 'https://media.retroachievements.org/Images/078809.png', 'https://media.retroachievements.org/Images/024306.png', 'https://media.retroachievements.org/Images/023627.png', 'https://media.retroachievements.org/Images/023709.png', 4.1),
  (168, 14331, '~Hack~ Super Mario Fallen Stars', 'Nintendo 64', 2, 260, 260, 260, 18, 0, NULL, 'Skillux', 'Hack - Super Mario 64', '2013-03-01', 'Super Mario is a platform game series developed and published by Nintendo and starring their mascot, Mario. The series was created by Japanese game designer Shigeru Miyamoto and is the flagship series of the greater Mario franchise. At least one Super Mario game has been released for every major Nintendo video game console. A limited number of Super Mario games have also released on non-Nintendo gaming platforms.', 'https://media.retroachievements.org/Images/025176.png', 'https://media.retroachievements.org/Images/025005.png', 'https://media.retroachievements.org/Images/025000.png', 'https://media.retroachievements.org/Images/025002.png', 4.1),
  (169, 10520, 'Turok 2: Seeds of Evil', 'Nintendo 64', 2, 258, 258, 258, 42, 0, 'First-Person Shooter', 'Iguana Entertainment', 'Acclaim', '1998-12-21', 'Turok 2: Seeds of Evil is a first-person shooter video game developed by Iguana Entertainment and published by Acclaim Entertainment. It was released for the Nintendo 64 console in 1998 and ported to Microsoft Windows computers in 1999. Seeds of Evil is the second game in the Turok video game series and a sequel to Turok: Dinosaur Hunter. The game follows the story of a Turok and his efforts to stop a powerful alien entity from escaping the confines of his Lightship. A different game set in the same fictional universe, also titled Turok 2: Seeds of Evil, was released for the Game Boy Color alongside the Nintendo 64 game.', 'https://media.retroachievements.org/Images/015809.png', 'https://media.retroachievements.org/Images/015806.png', 'https://media.retroachievements.org/Images/015807.png', 'https://media.retroachievements.org/Images/015808.png', 4),
  (170, 34006, '~Hack~ Hero of Law', 'Nintendo 64', 2, 251, 251, 251, 48, 0, 'Mystery, Visual Novel', 'Hacker - Newer Team', 'Hack - The Legend of Zelda: Ocarina of Time', '2025-06-28', 'The Legend of Zelda is a video game series created by Japanese game designers Shigeru Miyamoto and Takashi Tezuka. It is primarily developed and published by Nintendo, but some installments and re-releases have been outsourced to Flagship, Grezzo, and Tantalus Media.', 'https://media.retroachievements.org/Images/115365.png', 'https://media.retroachievements.org/Images/115407.png', 'https://media.retroachievements.org/Images/115041.png', 'https://media.retroachievements.org/Images/115283.png', 4),
  (171, 30717, '~Hack~ The Legend of Zelda: Time Lost', 'Nintendo 64', 2, 248, 248, 248, 62, 0, NULL, 'StoneeBadLuck', NULL, '2024-08-08', 'The Legend of Zelda: Ocarina of Time is a 1998 action-adventure game developed and published by Nintendo for the Nintendo 64. It was the first Legend of Zelda game with 3D graphics. It was released in Japan and North America in November 1998 and in PAL regions the following month.', 'https://media.retroachievements.org/Images/101484.png', 'https://media.retroachievements.org/Images/106009.png', 'https://media.retroachievements.org/Images/101289.png', 'https://media.retroachievements.org/Images/101475.png', 4),
  (172, 20029, '~Hack~ Cooking Princess', 'Nintendo 64', 2, 247, 247, 247, 12, 0, 'Cooking Simulation', 'elDexter', 'Hack - Paper Mario', '2022-06-18', 'Homebrew is a term for software produced by hobbyists for proprietary video game consoles, which are not intended to be user-programmable.', 'https://media.retroachievements.org/Images/060611.png', 'https://media.retroachievements.org/Images/060612.png', 'https://media.retroachievements.org/Images/059905.png', 'https://media.retroachievements.org/Images/059906.png', 4),
  (173, 10165, 'Indiana Jones and the Infernal Machine', 'Nintendo 64', 2, 246, 246, 246, 77, 0, 'Action-Adventure', 'Factor 5, LucasArts | Lucasfilm', 'LucasArts | Lucasfilm', '2000-12-15', 'Indiana Jones and the Infernal Machine is a 1999 action-adventure video game developed and published by LucasArts. The first 3D installment in the series, its gameplay focuses on solving puzzles, fighting enemies, and completing various platforming sections. The story is set in 1947, after the events of Indiana Jones and the Iron Phoenix, and puts the eponymous protagonist, the adventurer Indiana Jones, against the Soviet Union. In a race for a mythological Babylonian power source, he joins forces with the Central Intelligence Agency and collects four pieces of the Infernal Machine, an ancient device that allegedly opens a portal to another dimension.', 'https://media.retroachievements.org/Images/099146.png', 'https://media.retroachievements.org/Images/023930.png', 'https://media.retroachievements.org/Images/099144.png', 'https://media.retroachievements.org/Images/099145.png', 4),
  (174, 14663, '~Hack~ Super Mario 64: Peach''s Memory', 'Nintendo 64', 2, 245, 245, 245, 25, 0, '3D Platforming, Collect-a-thon', 'Daniel EDC', 'Hack - Super Mario 64', '2019-08-21', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/027669.png', 'https://media.retroachievements.org/Images/027670.png', 'https://media.retroachievements.org/Images/027538.png', 'https://media.retroachievements.org/Images/027664.png', 4),
  (175, 17501, '~Hack~ Star Revenge 1.5: Star Takeover Redone', 'Nintendo 64', 2, 241, 241, 241, 60, 0, '3D Platforming', 'Hacker - BroDute', 'Hack - Super Mario 64', '2015-08-14', 'Paramount Pictures Corporation, commonly known as Paramount Pictures or simply Paramount, is an American film production and distribution company and the flagship namesake subsidiary of Paramount Skydance. Founded on May 8, 1912, it is the sixth-oldest global film studio and the second-oldest in the United States behind Universal Pictures, and it is one of the Big Five studios located within the city limits of Los Angeles.', 'https://media.retroachievements.org/Images/058012.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/058010.png', 'https://media.retroachievements.org/Images/058011.png', 4),
  (176, 11437, '~Hack~ Super Mario 64: Halloween Mayhem', 'Nintendo 64', 2, 241, 241, 241, 8, 0, '3D Platforming', 'Hacker - Kaze Emanuar, Kinopio', 'Hack - Super Mario 64', '2014-10-31', '   Consolevania is a Scottish internet television with a magazine format, dedicated to video game reviews, gaming features, and comedy sketches based on gaming culture. The show''s format was adapted for mainstream television as the BBC Scotland show videoGaiden, featuring the same creative team, while episodes of Consolevania continued to be produced and distributed online as time permitted.', 'https://media.retroachievements.org/Images/064972.png', 'https://media.retroachievements.org/Images/025048.png', 'https://media.retroachievements.org/Images/025045.png', 'https://media.retroachievements.org/Images/025046.png', 4),
  (177, 14739, '~Hack~ Paper Mario: Master Quest', 'Nintendo 64', 2, 239, 239, 239, 68, 0, 'Turn-Based RPG', 'Emperor_Thamz, Rain, JaThePlayer, Brotenko,Purseit', 'Hack - Paper Mario', '2019-04-20', 'Paper Mario is a video game series and part of the Mario franchise, developed by Intelligent Systems and published by Nintendo. It combines elements from the role-playing, action-adventure, and puzzle genres. Players control a paper cutout version of Mario, usually with allies, on a quest to defeat the antagonist. The series consists of six games and one spin-off; the first, Paper Mario (2000), was released for the Nintendo 64, and the most recent, a 2024 remake of 2004''s Paper Mario: The Thousand-Year Door, for the Nintendo Switch.', 'https://media.retroachievements.org/Images/101844.png', 'https://media.retroachievements.org/Images/028298.png', 'https://media.retroachievements.org/Images/028297.png', 'https://media.retroachievements.org/Images/105225.png', 4),
  (178, 17748, '~Hack~ Super Mario Sunshine 64', 'Nintendo 64', 2, 238, 238, 238, 20, 0, '3D Platforming', 'Team Cornersoft', 'Hack - Super Mario 64', '2020-02-13', 'Super Mario 64 is a 1996 platform game developed and published by Nintendo for the Nintendo 64. It is the first Super Mario game to feature 3D gameplay, combining traditional Super Mario gameplay, visual style, and characters in a large open world. In the game, Bowser invades Princess Peach''s castle, kidnaps her, and hides the castle''s sources of protection, the Power Stars, in many different worlds inside magical paintings. As Mario, the player traverses levels and collects Power Stars to unlock areas of Princess Peach''s castle, to reach Bowser and rescue Princess Peach.', 'https://media.retroachievements.org/Images/046584.png', 'https://media.retroachievements.org/Images/045309.png', 'https://media.retroachievements.org/Images/044855.png', 'https://media.retroachievements.org/Images/045660.png', 4),
  (179, 10652, '~Hack~ Paper Mario: Pro Mode', 'Nintendo 64', 2, 237, 237, 237, 75, 0, 'Turn-Based RPG', 'Clover', 'Hack - Paper Mario', '2017-07-17', 'Paper Mario is a 2000 role-playing video game developed by Intelligent Systems and published by Nintendo for the Nintendo 64 home video game console. Paper Mario is the first game in the Paper Mario series. First released in Japan in 2000 and then internationally in 2001, Paper Mario was later re-released for Nintendo''s Wii Virtual Console in July 2007, the Wii U Virtual Console in April 2015, and the Nintendo Classics service on December 10, 2021.', 'https://media.retroachievements.org/Images/112153.png', 'https://media.retroachievements.org/Images/024945.png', 'https://media.retroachievements.org/Images/024940.png', 'https://media.retroachievements.org/Images/024946.png', 4),
  (180, 13387, '~Hack~ Banjo-Kazooie: Gruntylvania', 'Nintendo 64', 2, 233, 233, 233, 7, 0, NULL, 'Hacker - Kurko Mods', NULL, '2022-10-01', NULL, 'https://media.retroachievements.org/Images/084682.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/084679.png', 'https://media.retroachievements.org/Images/084680.png', 4),
  (181, 35528, '~Hack~ The Slideverse', 'Nintendo 64', 2, 229, 229, 229, 20, 0, '3D Platforming', 'JakeDower', 'Hack - Super Mario 64', '2024-04-01', NULL, 'https://media.retroachievements.org/Images/119651.png', 'https://media.retroachievements.org/Images/119649.png', 'https://media.retroachievements.org/Images/119648.png', 'https://media.retroachievements.org/Images/119647.png', 4),
  (182, 10126, 'Tony Hawk''s Pro Skater 3', 'Nintendo 64', 2, 229, 229, 229, 49, 0, 'Extreme Sports - Skateboarding', 'Neversoft, Edge of Reality', 'Activision', '2002-08-20', 'Tony Hawk''s Pro Skater 3 is a 2001 skateboarding video game and the third installment in the Tony Hawk''s series. It was published by Activision under the Activision O2 label in 2001 for the PlayStation, PlayStation 2, Game Boy Color and GameCube. In 2002, it was published for the Xbox, Game Boy Advance, Windows, Mac OS, and the Nintendo 64. It was the final official release for the Nintendo 64 and the only game that was released for the system in 2002, the first game released for the PlayStation 2 supporting online play and was a launch title for the GameCube in North America and PAL regions.', 'https://media.retroachievements.org/Images/047928.png', 'https://media.retroachievements.org/Images/011060.png', 'https://media.retroachievements.org/Images/011057.png', 'https://media.retroachievements.org/Images/011058.png', 4),
  (183, 10471, '~Hack~ The Legend of Banjo-Kazooie: The Bear Waker Deluxe', 'Nintendo 64', 2, 228, 228, 228, 12, 0, '3D Platforming', 'Hacker - Kurko Mods', 'Hack - Banjo-Kazooie', '2019-01-01', ' This is a list of Xbox 360 games (A-L) that were released via retail disc, digital download or as part of the Xbox Live Arcade program.', 'https://media.retroachievements.org/Images/046318.png', 'https://media.retroachievements.org/Images/044076.png', 'https://media.retroachievements.org/Images/101485.png', 'https://media.retroachievements.org/Images/044103.png', 4),
  (184, 11530, 'Dance Dance Revolution: Disney Dancing Museum', 'Nintendo 64', 2, 226, 226, 226, 44, 0, 'Rhythm', 'Konami', 'Disney Interactive Studios', '2000-11-30', ' The Dance Dance Revolution series started in 1998 and has grown to a large set of games in the franchise. This list of Dance Dance Revolution games documents games released, including systems, formats, and regions for which the games were released.', 'https://media.retroachievements.org/Images/044306.png', 'https://media.retroachievements.org/Images/018372.png', 'https://media.retroachievements.org/Images/018373.png', 'https://media.retroachievements.org/Images/018374.png', 4),
  (185, 14625, '~Hack~ Mario''s Little Odyssey', 'Nintendo 64', 2, 223, 223, 223, 14, 0, '3D Platforming', 'Hacker - Kaze Emanuar', 'Hack - Super Mario 64', '2018-07-10', 'Super Mario is a platform game series developed and published by Nintendo and starring their mascot, Mario. The series was created by Japanese game designer Shigeru Miyamoto and is the flagship series of the greater Mario franchise. At least one Super Mario game has been released for every major Nintendo video game console. A limited number of Super Mario games have also released on non-Nintendo gaming platforms.', 'https://media.retroachievements.org/Images/027295.png', 'https://media.retroachievements.org/Images/042738.png', 'https://media.retroachievements.org/Images/027273.png', 'https://media.retroachievements.org/Images/027284.png', 4),
  (186, 14694, '~Hack~ Super Melee Adventure 64', 'Nintendo 64', 2, 222, 222, 222, 15, 0, '3D Platforming, Collect-a-thon', 'Hacker - Pasta Power', 'Hack - Super Mario 64', '2019-01-01', 'Super Smash Bros. is a 1999 crossover fighting game developed by HAL Laboratory and published by Nintendo for the Nintendo 64. It is the first game in the Super Smash Bros. series and was released in Japan on January 21, 1999; in North America on April 26, 1999; and in Europe on November 19, 1999. It was later released for the iQue Player in China on November 15, 2005.', 'https://media.retroachievements.org/Images/027887.png', 'https://media.retroachievements.org/Images/027888.png', 'https://media.retroachievements.org/Images/027817.png', 'https://media.retroachievements.org/Images/027886.png', 4),
  (187, 10466, 'Forsaken 64', 'Nintendo 64', 2, 220, 220, 220, 63, 0, 'First-Person Shooter', 'Iguana Entertainment', 'Acclaim', '1998-04-30', 'Forsaken is a 1998 shooter video game developed by Probe Entertainment and published by Acclaim Entertainment. It was released for Microsoft Windows and PlayStation, with a port to the Nintendo 64 developed by Iguana UK releasing the same year as Forsaken 64.', 'https://media.retroachievements.org/Images/047208.png', 'https://media.retroachievements.org/Images/025502.png', 'https://media.retroachievements.org/Images/025499.png', 'https://media.retroachievements.org/Images/097783.png', 4),
  (188, 10125, 'Tony Hawk''s Pro Skater 2', 'Nintendo 64', 2, 219, 219, 219, 35, 0, 'Extreme Sports - Skateboarding', 'Neversoft, Edge of Reality', 'Activision', '2001-08-21', 'Tony Hawk''s Pro Skater 2 is a 2000 skateboarding video game developed by Neversoft for PlayStation and Natsume for Game Boy Color. Published by Activision, it is the second installment in the Tony Hawk''s series of sports games, and was released for the PlayStation in 2000, with subsequent ports to Windows and Dreamcast alongside a distinct version for Game Boy Color the same year. In 2001, the game was ported to Mac OS, Mac OS X, Nintendo 64, and Xbox, alongside a separate version for Game Boy Advance by Vicarious Visions. The game was later ported to Windows Mobile and Windows Phone devices in 2006 and to iPhone OS devices in 2010.', 'https://media.retroachievements.org/Images/041741.png', 'https://media.retroachievements.org/Images/011051.png', 'https://media.retroachievements.org/Images/011049.png', 'https://media.retroachievements.org/Images/011050.png', 4),
  (189, 10332, 'WWF WrestleMania 2000', 'Nintendo 64', 2, 219, 219, 219, 39, 0, 'Sports - Wrestling', 'AKI | syn Sophia', 'THQ', '1999-10-31', 'WrestleMania 2000, also known as WrestleMania 16, was a professional wrestling pay-per-view (PPV) event produced by the World Wrestling Federation. It was the 16th annual WrestleMania, and took place on April 2, 2000, at the Arrowhead Pond of Anaheim in Anaheim, California. This was the second WrestleMania at this venue, after WrestleMania XII in 1996. A total of nine matches were contested on the event''s card.', 'https://media.retroachievements.org/Images/012052.png', 'https://media.retroachievements.org/Images/012053.png', 'https://media.retroachievements.org/Images/012051.png', 'https://media.retroachievements.org/Images/012055.png', 4),
  (190, 29859, '~Hack~ Banjo-Kongzooie', 'Nintendo 64', 2, 212, 212, 212, 16, 0, '3D Platforming, Collect-a-thon', 'GloriousLiar', 'Hack - Donkey Kong 64', '2023-03-20', NULL, 'https://media.retroachievements.org/Images/098053.png', 'https://media.retroachievements.org/Images/103163.png', 'https://media.retroachievements.org/Images/097925.png', 'https://media.retroachievements.org/Images/097927.png', 4),
  (191, 15805, '~Prototype~ Tamiya Racing 64', 'Nintendo 64', 2, 211, 211, 211, 8, 0, 'Racing', 'Looking Glass Studios', 'Looking Glass Studios', '2012-04-05', 'Over the years, the Tamiya Corporation has created a huge number of notable product lines. This article attempts to list them.', 'https://media.retroachievements.org/Images/031575.png', 'https://media.retroachievements.org/Images/031578.png', 'https://media.retroachievements.org/Images/031576.png', 'https://media.retroachievements.org/Images/031577.png', 4),
  (192, 10430, 'Rugrats: Scavenger Hunt', 'Nintendo 64', 2, 209, 209, 209, 31, 0, 'Board Game', 'Realtime Associates', 'THQ', '1999-06-29', 'Rugrats: Scavenger Hunt is a 1999 party video game developed by Realtime Associates and published by THQ for the Nintendo 64. The game is based on the Nickelodeon animated television series Rugrats. It features the original voices from the Rugrats cast reprising their roles as Tommy Pickles, Chuckie Finster, and Phil and Lil DeVille as well as supporting characters Grandpa Lou, Didi and Stu Pickles, Susie Carmichael, Reptar, and series antagonist Angelica Pickles.', 'https://media.retroachievements.org/Images/063753.png', 'https://media.retroachievements.org/Images/026391.png', 'https://media.retroachievements.org/Images/026392.png', 'https://media.retroachievements.org/Images/026394.png', 4),
  (193, 31886, '~Hack~ Banjo-Kazooie: New Snow Glow Village', 'Nintendo 64', 2, 207, 207, 207, 12, 0, '3D Platforming, Collect-a-thon', 'Hacker - Kurko Mods, Koolboymon, Skill', 'Hack - Banjo-Kazooie', '2022-12-24', 'The following is a list of albums, EPs, and mixtapes released in the second half of 2021. These albums are (1) original, i.e. excluding reissues, remasters, and compilations of previously released recordings, and (2) notable, defined as having received significant coverage from reliable sources independent of the subject.', 'https://media.retroachievements.org/Images/105740.png', 'https://media.retroachievements.org/Images/105737.png', 'https://media.retroachievements.org/Images/105738.png', 'https://media.retroachievements.org/Images/105739.png', 4),
  (194, 10561, '~Hack~ Luigi''s Mansion 64', 'Nintendo 64', 2, 206, 206, 206, 37, 0, '3D Platforming', 'Lincrash', 'Hack - Super Mario 64', '2015-05-31', 'Nintendo Classics is a line of emulated retro games distributed by Nintendo for the Nintendo Switch and Nintendo Switch 2. Launched in 2018, subscribers of the Nintendo Switch Online service have access to games for the Nintendo Entertainment System (NES), Super Nintendo Entertainment System (SNES), Game Boy (GB) and Game Boy Color (GBC). A more expensive subscription tier, titled "Expansion Pack", was introduced in 2021. Through this tier, players can also access Nintendo 64 (N64), Sega Genesis (GEN), Game Boy Advance (GBA), and Virtual Boy (VB) games, with GameCube (GCN) exclusively available on Nintendo Switch 2. Each console''s library is accessed through a dedicated app, with new games being added on an irregular basis. Games are accessible as long as the user has an active subscription, and a user must connect to the internet at least once a week to continue to access services while offline.', 'https://media.retroachievements.org/Images/049691.png', 'https://media.retroachievements.org/Images/049385.png', 'https://media.retroachievements.org/Images/049382.png', 'https://media.retroachievements.org/Images/049383.png', 4),
  (195, 10325, 'WWF War Zone', 'Nintendo 64', 2, 206, 206, 206, 64, 0, 'Sports - Wrestling', 'Sculptured Software | Iguana West', 'Acclaim', '1998-08-11', 'WWF War Zone is a professional wrestling video game developed by Iguana West and released by Acclaim Entertainment in 1998 for the PlayStation, Nintendo 64, and Game Boy. The game features wrestlers from the World Wrestling Federation (WWF) and was the first graphical 3D game based on the WWF.', 'https://media.retroachievements.org/Images/070694.png', 'https://media.retroachievements.org/Images/070695.png', 'https://media.retroachievements.org/Images/070692.png', 'https://media.retroachievements.org/Images/070693.png', 4),
  (196, 10574, 'Custom Robo', 'Nintendo 64', 2, 205, 205, 205, 40, 0, '3D Arena Battler RPG', 'Noise', 'Nintendo', '1999-12-08', 'Custom Robo is an action role-playing video game series developed by Noise and published by Nintendo.', 'https://media.retroachievements.org/Images/062605.png', 'https://media.retroachievements.org/Images/015978.png', 'https://media.retroachievements.org/Images/015977.png', 'https://media.retroachievements.org/Images/015997.png', 4),
  (197, 30934, '~Hack~ Banjo-Kazooie: Bubbling Bog Brewery Redone', 'Nintendo 64', 2, 204, 204, 204, 7, 0, '3D Platforming, Collect-a-thon', 'Hacker - Kurko Mods', 'Hack - Banjo-Kazooie', '2023-10-31', NULL, 'https://media.retroachievements.org/Images/103195.png', 'https://media.retroachievements.org/Images/000002.png', 'https://media.retroachievements.org/Images/102464.png', 'https://media.retroachievements.org/Images/102465.png', 4),
  (198, 16228, '~Hack~ SimpleFlips'' 8th Hacking Competition: Creepypasta', 'Nintendo 64', 2, 199, 199, 199, 53, 0, '3D Platforming', 'Various', 'Hack - Super Mario 64', '2019-05-20', NULL, 'https://media.retroachievements.org/Images/033337.png', 'https://media.retroachievements.org/Images/033338.png', 'https://media.retroachievements.org/Images/033463.png', 'https://media.retroachievements.org/Images/033316.png', 4),
  (199, 19485, '~Hack~ Banjo-Kazooie: Cheato''s Challenges', 'Nintendo 64', 2, 198, 198, 198, 16, 0, '3D Platforming, Collect-a-thon', NULL, 'Hack - Banjo-Kazooie', '2022-03-01', 'Banjo-Kazooie is a 1998 platform game developed by Rare and published by Nintendo for the Nintendo 64. Controlling the player characters, the bear Banjo and the bird Kazooie, the player attempts to save Banjo''s kidnapped sister Tooty from the witch Gruntilda. The player explores nine nonlinear worlds to gather items and progress. Using Banjo and Kazooie''s traversal and combat abilities, they complete challenges such as solving puzzles, jumping over obstacles, and defeating bosses.', 'https://media.retroachievements.org/Images/063461.png', 'https://media.retroachievements.org/Images/066509.png', 'https://media.retroachievements.org/Images/063460.png', 'https://media.retroachievements.org/Images/063406.png', 4),
  (200, 36253, '~Hack~ Mario Adventure 2', 'Nintendo 64', 2, 196, 196, 196, 137, 0, NULL, 'aglab2', NULL, '2025-10-17', 'Paper Mario is a 2000 role-playing video game developed by Intelligent Systems and published by Nintendo for the Nintendo 64 home video game console. Paper Mario is the first game in the Paper Mario series. First released in Japan in 2000 and then internationally in 2001, Paper Mario was later re-released for Nintendo''s Wii Virtual Console in July 2007, the Wii U Virtual Console in April 2015, and the Nintendo Classics service on December 10, 2021.', 'https://media.retroachievements.org/Images/123212.png', 'https://media.retroachievements.org/Images/121743.png', 'https://media.retroachievements.org/Images/120316.png', 'https://media.retroachievements.org/Images/120319.png', 4);
